/// Exposed for test access.
#[cfg(test)]
pub fn builtin_primitives_for_test() -> Vec<BuiltinPrimitive> {
    builtin_primitives()
}

fn render_builtins_markdown(primitives: &[BuiltinPrimitive]) -> String {
    let mut out = String::from("# Favnir Built-in Primitives\n\n");
    let mut current_ns = "";
    for p in primitives {
        if p.namespace != current_ns {
            if !current_ns.is_empty() {
                out.push_str("---\n\n");
            }
            current_ns = p.namespace;
            out.push_str(&format!("## {}\n\n", p.namespace));
        }
        out.push_str(&format!("### {}\n", p.name));
        if p.effects.is_empty() {
            out.push_str(&format!("`{}`\n\n", p.signature));
        } else {
            out.push_str(&format!("`{}` {}\n\n", p.signature, p.effects.join(" ")));
        }
        out.push_str(p.description);
        out.push_str("\n\n");
    }
    out
}

pub fn cmd_doc_builtins(format: &str, out: Option<&str>) {
    let prims = builtin_primitives();
    let content = if format == "json" {
        serde_json::to_string_pretty(&prims).expect("builtin primitives json serialization")
    } else {
        render_builtins_markdown(&prims)
    };
    match out {
        Some(path) => {
            std::fs::write(path, &content)
                .unwrap_or_else(|e| { eprintln!("error: {}", e); process::exit(1); });
        }
        None => print!("{}", content),
    }
}

// ── fav explain <code> (v12.7.0) ─────────────────────────────────────────────

pub(crate) fn get_explain_text(code: &str) -> Option<&'static str> {
    match code {
        "E0001" => Some(
"E0001: Undefined variable

変数が定義される前に使用されています。
スペルミスか、定義より前に参照しているケースが多いです。

修正例:
  誤: bind result <- transform(rows)   ← rows が未定義

  正: bind rows   <- load_data()
      bind result <- transform(rows)   ← OK

関連: E0007（未定義関数）"
        ),
        "E0007" => Some(
"E0007: Undefined function

呼び出している関数が見つかりません。
Namespace の指定ミス、import 漏れが原因のことが多いです。

修正例:
  誤: bind r <- Csv.Parse(text)    ← 大文字・スペルミス

  正: bind r <- Csv.parse_raw(text, \",\", true)   ← OK

関連: E0001（未定義変数）"
        ),
        "E0008" => Some(
"E0008: Wrong number of arguments

関数呼び出しの引数の数が定義と一致しません。

修正例:
  誤: bind r <- Csv.parse_raw(text)       ← 引数が 1 つ（3 つ必要）

  正: bind r <- Csv.parse_raw(text, \",\", true)   ← OK"
        ),
        "E0009" => Some(
"E0009: Return type mismatch

関数・stage の宣言した戻り型と実際の戻り値の型が一致しません。

修正例:
  誤: stage MyStage: String -> Int !IO = |s| { s }   ← String を返している

  正: stage MyStage: String -> String !IO = |s| { s }   ← OK"
        ),
        "E0012" => Some(
"E0012: Type mismatch

式の型が期待される型と一致しません。

修正例:
  誤: bind n <- Int.add(\"hello\", 1)   ← String を Int に渡している

  正: bind n <- Int.add(42, 1)   ← OK"
        ),
        "E0013" => Some(
"E0013: Where constraint violation

`where` バリデーターの条件を満たしていません。

修正例:
  type Age(Int) where v > 0 and v < 150

  誤: bind age <- Age(-1)   ← E0013

  正: bind age <- Age(25)   ← OK"
        ),
        "E0014" => Some(
"E0014: Interface not implemented

型が `interface` の実装（`impl`）を持っていません。

修正例:
  interface Printable { fn print(self) -> Unit }

  誤: 実装なしで Printable として使用   ← E0014

  正: impl Printable for MyType { fn print(self) -> Unit = ... }   ← OK"
        ),
        "E0015" => Some(
"E0015: Method not found

型に指定のメソッドが定義されていません。

修正例:
  誤: bind r <- my_val.unknown_method()   ← E0015

  正: bind r <- my_val.to_string()   ← OK（定義済みのメソッド）"
        ),
        "E0016" => Some(
"E0016: Effect not declared

stage / fn 宣言の `!Effect` に含まれないエフェクトを内部で使用しています。

修正例:
  誤: stage MyStage: String -> String = |s| {
        bind _ <- IO.println(s)   ← !IO が宣言にない → E0016
        s
      }

  正: stage MyStage: String -> String !IO = |s| {
        bind _ <- IO.println(s)   ← OK
        s
      }

関連: E0017（不要なエフェクト宣言）"
        ),
        "E0017" => Some(
"E0017: Unused effect declaration

宣言した `!Effect` が実際に使われていません。

修正例:
  誤: stage MyStage: String -> String !IO !Postgres = |s| { s }
      ← !IO と !Postgres を宣言しているが使っていない → E0017

  正: stage MyStage: String -> String = |s| { s }   ← OK

関連: E0016（エフェクト宣言漏れ）"
        ),
        "E0018" => Some(
"E0018: Variable already bound

Favnir では変数は一度だけ束縛できます（イミュータブル）。
同一スコープで bind x を 2 回書くことはできません。

修正例:
  誤: bind x <- step1()
      bind x <- step2(x)   ← E0018

  正: bind x  <- step1()
      bind x2 <- step2(x)  ← OK
      または:
      bind _ <- step2(x)   ← 結果を捨てる場合（W006 に注意）

関連: W006（Result を bind _ で捨てる）"
        ),
        "W001" => Some(
"W001: Unused variable

束縛した変数が一度も使われていません。

修正例:
  誤: bind unused <- compute()   ← W001

  正: bind _ <- compute()   ← 意図的に捨てる場合
      または変数を実際に使う"
        ),
        "W002" => Some(
"W002: Unreachable code

到達しないコードが存在します。

修正例:
  誤: bind x <- step()
      x
      \"never reached\"   ← W002

  正: コードを削除するか、フロー制御を見直す"
        ),
        "W003" => Some(
"W003: Redundant match arm

match のあるアームが他のアームと重複しています。"
        ),
        "W004" => Some(
"W004: Magic string / number

ハードコードされた文字列・数値が複数箇所に出現しています。
定数や設定に切り出すことを検討してください。"
        ),
        "W005" => Some(
"W005: Deep nesting

match や if のネストが深すぎます。
ヘルパー stage / fn に切り出すことを検討してください。"
        ),
        "W006" => Some(
"W006: Discarding Result value

bind _ <- Postgres.execute_raw(...) のように、
エフェクトが返す Result を bind _ で捨てると警告が出ます。
失敗がサイレントに通過し、パイプラインが誤動作する原因になります。

修正例:
  誤: bind _ <- Postgres.execute_raw(sql, params)   ← W006

  正: chain _ <- Postgres.execute_raw(sql, params)  ← エラーを自動伝播
      または:
      match Postgres.execute_raw(sql, params) {
        Ok(_)  => \"ok\"
        Err(e) => e
      }

関連: E0018（変数の再束縛）"
        ),
        "W007" => Some(
"W007: Shadowed binding

外側のスコープと同じ名前の変数を内側で束縛しています。
意図しない名前衝突の可能性があります。

修正例:
  誤: bind x <- outer()
      match x {
        Ok(x) => x   ← 外側の x を shadow → W007
        Err(e) => e
      }

  正: match x {
        Ok(v) => v   ← 別名を使う
        Err(e) => e
      }"
        ),
        _ => None,
    }
}

pub fn cmd_explain_code(code: &str) {
    match get_explain_text(code) {
        Some(text) => println!("{}", text),
        None => {
            eprintln!("unknown error code: {}", code);
            process::exit(1);
        }
    }
}

// ── fav scaffold ──────────────────────────────────────────────────────────────

fn scaffold_stage(name: &str, in_type: &str, out_type: &str, effect: Option<&str>) -> String {
    let effect_ann = match effect {
        Some(e) => format!(" !{}", e),
        None => String::new(),
    };
    let body = match effect {
        Some(_) => "    bind _result <- IO.println(input)\n    input\n".to_string(),
        None => "    input\n".to_string(),
    };
    format!(
        "// {name}: {in_type} -> {out_type}{effect_ann}\n\
         // TODO: implement {name}\n\
         public stage {name}: {in_type} -> {out_type}{effect_ann} = |input| {{\n\
         {body}}}\n"
    )
}

fn scaffold_seq(name: &str, stages: &[&str]) -> String {
    let mut out = format!(
        "// {name}: String -> String\n// {}-stage sequential pipeline\n",
        stages.len()
    );
    for (i, stage) in stages.iter().enumerate() {
        let is_first = i == 0;
        let is_last = i == stages.len() - 1;
        let effect_ann = if is_first || is_last { " !IO" } else { "" };
        let param = if is_first { "input" } else { "data" };
        let todo = if is_first {
            "// TODO: load data"
        } else if is_last {
            "// TODO: save results"
        } else {
            "// TODO: transform data"
        };
        out.push_str(&format!(
            "\npublic stage {stage}: String -> String{effect_ann} = |{param}| {{\n    {todo}\n    {param}\n}}\n"
        ));
    }
    let pipe_chain = stages.join(" |> ");
    out.push_str(&format!("\npublic seq {name} = {pipe_chain}\n"));
    out
}

fn scaffold_postgres_etl() -> String {
    r#"// Postgres ETL pipeline — best practice template (v12.8.0)
// Uses chain for error propagation and seq for fail-fast execution.

public stage LoadCsv: String -> String !IO = |path| {
    match IO.read_file_raw(path) {
        Ok(text) => text
        Err(e)   => e
    }
}

public stage InsertRows: String -> String !IO !Postgres = |csv_text| {
    match Csv.parse_raw(csv_text, ",", true) {
        Ok(rows) => {
            bind json <- Schema.to_json_array(rows, "Row")
            bind sql  <- $"INSERT INTO my_table (data) VALUES ('{json}')"
            match Postgres.execute_raw(sql, "[]") {
                Ok(_)  => $"inserted rows"
                Err(e) => e
            }
        }
        Err(e) => e
    }
}

public stage SaveResult: String -> String !IO = |result| {
    chain _ <- IO.write_file_raw("/tmp/result.txt", result)
    result
}

public seq EtlPipeline = LoadCsv |> InsertRows |> SaveResult
"#
    .to_string()
}

fn scaffold_rune(name: &str) -> String {
    format!(
        "// {name} rune — public API\n\
         // Usage: import {name} from \"path/to/{lower}\"\n\
         \n\
         public fn hello(name: String) -> String {{\n\
             $\"Hello from {name}, {{name}}!\"\n\
         }}\n",
        name = name,
        lower = name.to_lowercase()
    )
}

fn write_scaffold(content: &str, out: Option<&str>) {
    match out {
        Some(path) => {
            std::fs::write(path, content)
                .unwrap_or_else(|e| { eprintln!("error: cannot write {}: {}", path, e); process::exit(1); });
        }
        None => print!("{}", content),
    }
}

pub fn cmd_scaffold(sub: &str, args: &[String]) {
    // parse common flags
    let mut in_type = "String";
    let mut out_type = "String";
    let mut effect: Option<&str> = Some("IO");
    let mut no_effect = false;
    let mut out_file: Option<&str> = None;
    let mut stages_str: Option<&str> = None;
    let mut i = 1usize; // args[0] = Name (positional), args[1..] = flags
    while i < args.len() {
        match args[i].as_str() {
            "--in"        => { in_type   = args.get(i+1).map(|s| s.as_str()).unwrap_or("String"); i += 2; }
            "--out-type"  => { out_type  = args.get(i+1).map(|s| s.as_str()).unwrap_or("String"); i += 2; }
            "--effect"    => { effect    = Some(args.get(i+1).map(|s| s.as_str()).unwrap_or("IO")); i += 2; }
            "--no-effect" => { no_effect = true; i += 1; }
            "--out"       => { out_file  = args.get(i+1).map(|s| s.as_str()); i += 2; }
            "--stages"    => { stages_str = args.get(i+1).map(|s| s.as_str()); i += 2; }
            _             => { i += 1; }
        }
    }
    if no_effect { effect = None; }

    match sub {
        "stage" => {
            let name = args.first().map(|s| s.as_str()).unwrap_or("MyStage");
            let content = scaffold_stage(name, in_type, out_type, effect);
            write_scaffold(&content, out_file);
        }
        "seq" => {
            let name = args.first().map(|s| s.as_str()).unwrap_or("MyPipeline");
            let default_stages = vec!["Load", "Transform", "Save"];
            let custom: Vec<String>;
            let stage_refs: Vec<&str> = if let Some(s) = stages_str {
                custom = s.split(',').map(|x| x.trim().to_string()).collect();
                custom.iter().map(|x| x.as_str()).collect()
            } else {
                default_stages
            };
            let content = scaffold_seq(name, &stage_refs);
            write_scaffold(&content, out_file);
        }
        "postgres-etl" => {
            let content = scaffold_postgres_etl();
            write_scaffold(&content, out_file);
        }
        "rune" => {
            let name = args.first().map(|s| s.as_str()).unwrap_or("MyLib");
            let content = scaffold_rune(name);
            write_scaffold(&content, out_file);
        }
        other => {
            eprintln!("error: unknown scaffold template '{}' (expected stage|seq|postgres-etl|rune)", other);
            process::exit(1);
        }
    }
}

// ── fav doc ───────────────────────────────────────────────────────────────────

/// Generate Markdown documentation from .fav source files.
///
/// * `path`    — a `.fav` file or a directory (scanned recursively).
/// * `out_dir` — output directory for `.md` files (created if absent).
pub fn cmd_doc(path: &str, out_dir: &str) {
    let entries: Vec<PathBuf> = {
        let p = Path::new(path);
        if p.is_file() {
            vec![p.to_path_buf()]
        } else if p.is_dir() {
            collect_fav_files_recursive(p)
        } else {
            eprintln!("error: '{}' is not a file or directory", path);
            process::exit(1);
        }
    };

    if let Err(e) = std::fs::create_dir_all(out_dir) {
        eprintln!("error: cannot create output directory '{}': {}", out_dir, e);
        process::exit(1);
    }

    for entry in &entries {
        let src = match std::fs::read_to_string(entry) {
            Ok(s) => s,
            Err(e) => {
                eprintln!("error: cannot read '{}': {}", entry.display(), e);
                process::exit(1);
            }
        };

        let md = match crate::compiler_fav_runner::doc_source_str(&src) {
            Ok(m) => m,
            Err(e) => {
                eprintln!("error: doc failed for '{}': {}", entry.display(), e);
                process::exit(1);
            }
        };

        let stem = entry
            .file_stem()
            .map(|s| s.to_string_lossy().to_string())
            .unwrap_or_else(|| "out".to_string());
        let out_path = Path::new(out_dir).join(format!("{}.md", stem));
        if let Err(e) = std::fs::write(&out_path, &md) {
            eprintln!("error: cannot write '{}': {}", out_path.display(), e);
            process::exit(1);
        }
        println!("doc: {} → {}", entry.display(), out_path.display());
    }
}

// ── fav profile ───────────────────────────────────────────────────────────────

fn render_profile_table(json: &str) {
    #[derive(serde::Deserialize)]
    struct Record {
        name: String,
        ms: i64,
    }
    let records: Vec<Record> = serde_json::from_str(json).unwrap_or_default();
    if records.is_empty() {
        println!("(no stage calls recorded)");
        return;
    }
    let total: i64 = records.iter().map(|r| r.ms).sum();
    let total_f = total.max(1) as f64;
    let name_w = records.iter().map(|r| r.name.len()).max().unwrap_or(5).max(5);
    println!("{:<width$}  {:>10}  {:>6}", "Stage", "Time (ms)", "%", width = name_w);
    println!("{}", "─".repeat(name_w + 22));
    for r in &records {
        let pct = (r.ms as f64 / total_f * 100.0).round() as i64;
        println!("{:<width$}  {:>10}  {:>5}%", r.name, r.ms, pct, width = name_w);
    }
    println!("{}", "─".repeat(name_w + 22));
    println!("{:<width$}  {:>10}  {:>5}%", "Total", total, 100, width = name_w);
}

pub fn cmd_profile(path: &str, out_fmt: &str) {
    let src = match std::fs::read_to_string(path) {
        Ok(s) => s,
        Err(e) => {
            eprintln!("error: cannot read '{}': {}", path, e);
            process::exit(1);
        }
    };
    let bytes = match crate::compiler_fav_runner::compile_profiled_str(&src) {
        Ok(b) => b,
        Err(e) => {
            eprintln!("error: profile compile failed: {}", e);
            process::exit(1);
        }
    };
    crate::backend::vm::clear_profile_records();
    run_fvc_bytes(&bytes, None, Some(path));
    let json = crate::backend::vm::take_profile_dump_json();
    if out_fmt == "json" {
        println!("{}", json);
    } else {
        render_profile_table(&json);
    }
}

// ── fav explain ───────────────────────────────────────────────────────────────

pub fn cmd_explain(file: Option<&str>, schema: bool, format: &str, focus: &str) {
    if let Some(path) = file {
        if path.ends_with(".fvc") {
            let artifact = read_artifact_from_path(Path::new(path)).unwrap_or_else(|message| {
                eprintln!("{message}");
                process::exit(1);
            });
            if schema {
                eprintln!("error: --schema is not supported for .fvc artifacts");
                process::exit(1);
            }
            if format == "json" {
                match explain_json_from_artifact(&artifact) {
                    Ok(json) => print!("{json}"),
                    Err(message) => {
                        eprintln!("{message}");
                        process::exit(1);
                    }
                }
            } else {
                print!("{}", artifact_info_string(&artifact));
            }
            return;
        }
    }

    let paths: Vec<String> = if let Some(f) = file {
        vec![f.to_string()]
    } else {
        let cwd = std::env::current_dir().unwrap_or_else(|_| PathBuf::from("."));
        let root = FavToml::find_root(&cwd).unwrap_or_else(|| {
            eprintln!("error: no fav.toml found");
            process::exit(1);
        });
        let toml = FavToml::load(&root).unwrap_or_else(|| {
            eprintln!("error: could not read fav.toml");
            process::exit(1);
        });
        collect_fav_files(&toml.src_dir(&root))
            .into_iter()
            .map(|p| p.to_string_lossy().to_string())
            .collect()
    };

    for path in &paths {
        let source = load_file(path);
        let program = Parser::parse_str(&source, path).unwrap_or_else(|e| {
            eprintln!("{}", e);
            process::exit(1);
        });
        let (errors, _) = Checker::check_program(&program);
        if !errors.is_empty() {
            eprintln!(
                "warning: {} type error(s) in `{}` — output may be incomplete",
                errors.len(),
                path
            );
        }
        if paths.len() > 1 {
            println!("\n=== {} ===", path);
        }
        // Best-effort IR compilation for DEPS collection (may fail on type errors)
        let ir = if errors.is_empty() {
            Some(compile_program(&program))
        } else {
            None
        };
        let include_stdlib_states = program.uses.iter().any(|use_path| {
            use_path.len() >= 2 && use_path[..use_path.len() - 1].join(".") == "std.states"
        });
        if schema {
            print!(
                "{}",
                ExplainPrinter::new().render_schema(&program, include_stdlib_states)
            );
        } else if format == "json" {
            let reachability = ir.as_ref().map(|ir_program| {
                crate::middle::reachability::reachability_analysis("main", ir_program)
            });
            print!(
                "{}",
                ExplainPrinter::new().render_json(
                    &program,
                    ir.as_ref(),
                    include_stdlib_states,
                    focus,
                    path,
                    reachability.as_ref(),
                )
            );
        } else {
            ExplainPrinter::new().print(&program, ir.as_ref(), include_stdlib_states);
        }
    }
}

#[derive(Debug, Clone, Serialize)]
struct ChangedEntry {
    name: String,
    diffs: Vec<String>,
}

#[derive(Debug, Clone, Serialize, Default)]
struct CategoryDiff {
    added: Vec<serde_json::Value>,
    removed: Vec<serde_json::Value>,
    changed: Vec<ChangedEntry>,
}

#[derive(Debug, Clone, Serialize)]
struct ExplainDiff {
    from_label: String,
    to_label: String,
    fn_changes: CategoryDiff,
    trf_changes: CategoryDiff,
    flw_changes: CategoryDiff,
    type_changes: CategoryDiff,
    effects_added: Vec<String>,
    effects_removed: Vec<String>,
    breaking_changes: Vec<String>,
}

pub fn cmd_explain_diff(from_path: &str, to_path: &str, format: &str) {
    let from = load_explain_json(from_path);
    let to = load_explain_json(to_path);
    let diff = diff_explain_json(from_path, &from, to_path, &to);
    if format == "json" {
        print!("{}", render_diff_json(&diff));
    } else {
        print!("{}", render_diff_text(&diff));
    }
}

fn load_explain_json(path: &str) -> serde_json::Value {
    try_load_explain_json(path).unwrap_or_else(|message| {
        eprintln!("{message}");
        process::exit(1);
    })
}

fn try_load_explain_json(path: &str) -> Result<serde_json::Value, String> {
    if path.ends_with(".json") {
        let text = load_file(path);
        serde_json::from_str(&text)
            .map_err(|e| format!("error: invalid explain json `{}`: {}", path, e))
    } else if path.ends_with(".fvc") {
        let artifact = read_artifact_from_path(Path::new(path))?;
        let text = explain_json_from_artifact(&artifact)?;
        serde_json::from_str(&text)
            .map_err(|e| format!("error: invalid embedded explain json `{}`: {}", path, e))
    } else {
        let (program, source_path) = load_and_check_program(Some(path));
        let ir = compile_program(&program);
        let reachability = crate::middle::reachability::reachability_analysis("main", &ir);
        let rendered = ExplainPrinter::new().render_json(
            &program,
            Some(&ir),
            true,
            "all",
            &source_path,
            Some(&reachability),
        );
        serde_json::from_str(&rendered)
            .map_err(|e| format!("error: invalid generated explain json `{}`: {}", path, e))
    }
}

pub fn get_explain_json(file: &str) -> Result<String, String> {
    let value = try_load_explain_json(file)?;
    serde_json::to_string(&value)
        .map_err(|e| format!("error: could not serialize explain json: {}", e))
}

fn empty_explain_json() -> String {
    json!({
        "schema_version": "3.0",
        "favnir_version": env!("CARGO_PKG_VERSION"),
        "file": serde_json::Value::Null,
        "effects_used": [],
        "fns": [],
        "stages": [],
        "seqs": [],
        "types": []
    })
    .to_string()
}

pub fn cmd_docs(file: Option<&str>, port: u16, no_open: bool) {
    let explain_json = match file {
        Some(path) => get_explain_json(path).unwrap_or_else(|message| {
            eprintln!("{message}");
            process::exit(1);
        }),
        None => empty_explain_json(),
    };

    let url = format!("http://localhost:{}", port);
    println!("Favnir docs server running at {}", url);
    if !no_open {
        let _ = open::that(&url);
    }

    let server = DocsServer::new(port);
    if let Err(message) = server.start(explain_json) {
        eprintln!("{message}");
        process::exit(1);
    }
}

// ── fav repl (v9.10.0) ───────────────────────────────────────────────────────

struct ReplSession {
    definitions: String,
    def_names: Vec<String>,
    history: Vec<String>, // v17.5.0
}

impl ReplSession {
    fn new() -> Self {
        Self { definitions: String::new(), def_names: Vec::new(), history: Vec::new() }
    }
    fn reset(&mut self) {
        self.definitions.clear();
        self.def_names.clear();
        self.history.clear();
        println!("session reset");
    }
    fn add_definition(&mut self, src: &str, name: &str) {
        if !self.definitions.is_empty() {
            self.definitions.push('\n');
        }
        self.definitions.push_str(src);
        self.definitions.push('\n');
        self.def_names.push(name.to_string());
    }
    fn add_history(&mut self, line: &str) {
        self.history.push(line.to_string());
    }
    fn print_history(&self) {
        if self.history.is_empty() {
            println!("(no history)");
        } else {
            for (i, line) in self.history.iter().enumerate() {
                println!("{}: {}", i + 1, line);
            }
        }
    }
}

