    fn nested_and_then_expr(depth: usize) -> String {
        let mut expr = "0".to_string();
        for i in (0..depth).rev() {
            expr = format!(
                "Result.and_then(foo{}, |v{}| {})",
                i, i, expr
            );
        }
        expr
    }

