// ── stdlib_v91_tests (v9.1.0) ─────────────────────────────────────────────────
#[cfg(test)]
mod stdlib_v91_tests {
    use crate::backend::vm::VM;
    use crate::backend::artifact::FvcArtifact;
    use crate::backend::codegen::codegen_program;
    use crate::frontend::parser::Parser;
    use crate::middle::compiler::compile_program;
    use crate::value::Value;

    fn run_fn(src: &str, fname: &str, args: Vec<Value>) -> Value {
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let ir = compile_program(&prog);
        let artifact: FvcArtifact = codegen_program(&ir);
        let fn_idx = artifact.fn_idx_by_name(fname).expect("fn not found");
        VM::run(&artifact, fn_idx, args).expect("VM error")
    }

    // F-1: List.zip_with — pairwise addition
    #[test]
    fn list_zip_with_add() {
        let src = r#"
fn zip_add(xs: List<Int>, ys: List<Int>) -> List<Int> {
    List.zip_with(|x| |y| x + y, xs, ys)
}
"#;
        let xs = Value::List(vec![Value::Int(1), Value::Int(2), Value::Int(3)]);
        let ys = Value::List(vec![Value::Int(10), Value::Int(20), Value::Int(30)]);
        let result = run_fn(src, "zip_add", vec![xs, ys]);
        match result {
            Value::List(items) => {
                let ints: Vec<i64> = items.into_iter().map(|v| match v {
                    Value::Int(n) => n,
                    _ => panic!("expected Int"),
                }).collect();
                assert_eq!(ints, vec![11, 22, 33]);
            }
            _ => panic!("expected List"),
        }
    }

    // F-2: List.group_by — group strings by first char
    #[test]
    fn list_group_by_first_char() {
        let src = r#"
fn group_first(xs: List<String>) -> Map<String, List<String>> {
    List.group_by(|s| String.slice(s, 0, 1), xs)
}
"#;
        let xs = Value::List(vec![
            Value::Str("apple".to_string()),
            Value::Str("avocado".to_string()),
            Value::Str("banana".to_string()),
        ]);
        let result = run_fn(src, "group_first", vec![xs]);
        match result {
            Value::Record(m) => {
                assert!(m.contains_key("a"), "should have key 'a'");
                assert!(m.contains_key("b"), "should have key 'b'");
            }
            _ => panic!("expected Record/Map"),
        }
    }

    // F-3: String.truncate — truncates to max length with suffix
    #[test]
    fn string_truncate_basic() {
        let src = r#"
fn trunc(s: String) -> String {
    String.truncate(s, 5, "")
}
"#;
        let result = run_fn(src, "trunc", vec![Value::Str("hello world".to_string())]);
        match result {
            Value::Str(s) => assert_eq!(s, "hello"),
            _ => panic!("expected Str"),
        }
    }

    // F-4: String.truncate — no-op when shorter than max
    #[test]
    fn string_truncate_short() {
        let src = r#"
fn trunc_short(s: String) -> String {
    String.truncate(s, 20, "...")
}
"#;
        let result = run_fn(src, "trunc_short", vec![Value::Str("hi".to_string())]);
        match result {
            Value::Str(s) => assert_eq!(s, "hi"),
            _ => panic!("expected Str"),
        }
    }

    // F-5: String.trim_start / trim_end
    #[test]
    fn string_trim_start_end() {
        let src = r#"
fn do_trim_start(s: String) -> String { String.trim_start(s) }
fn do_trim_end(s: String) -> String   { String.trim_end(s) }
"#;
        let result = run_fn(src, "do_trim_start", vec![Value::Str("  hello".to_string())]);
        match &result {
            Value::Str(s) => assert_eq!(s, "hello"),
            _ => panic!("expected Str"),
        }
        let result2 = run_fn(src, "do_trim_end", vec![Value::Str("hello  ".to_string())]);
        match &result2 {
            Value::Str(s) => assert_eq!(s, "hello"),
            _ => panic!("expected Str"),
        }
    }

    // F-6: Result.all — collects Ok values
    #[test]
    fn result_all_ok() {
        let src = r#"
fn collect_ok() -> Result<List<Int>, String> {
    Result.all(List.push(List.push(List.push(List.empty(), Result.ok(3)), Result.ok(2)), Result.ok(1)))
}
"#;
        let result = run_fn(src, "collect_ok", vec![]);
        match result {
            Value::Variant(tag, payload) => {
                assert_eq!(tag, "ok");
                match payload {
                    Some(inner) => match *inner {
                        Value::List(items) => assert_eq!(items.len(), 3),
                        _ => panic!("expected List inside ok"),
                    },
                    None => panic!("expected payload"),
                }
            }
            _ => panic!("expected Variant(ok)"),
        }
    }

    // F-7: Result.all — short-circuits on first Err
    #[test]
    fn result_all_err() {
        let src = r#"
fn collect_err() -> Result<List<Int>, String> {
    Result.all(List.push(List.push(List.empty(), Result.err("bad")), Result.ok(1)))
}
"#;
        let result = run_fn(src, "collect_err", vec![]);
        match result {
            Value::Variant(tag, _) => assert_eq!(tag, "err"),
            _ => panic!("expected Variant(err)"),
        }
    }

    // F-8: Map.filter — keeps matching keys
    #[test]
    fn map_filter_basic() {
        let src = r#"
fn map_filt(m: Map<String, Int>) -> Map<String, Int> {
    Map.filter(|k| |v| v > 1, m)
}
"#;
        let mut m = std::collections::HashMap::new();
        m.insert("a".to_string(), Value::Int(1));
        m.insert("b".to_string(), Value::Int(2));
        m.insert("c".to_string(), Value::Int(3));
        let result = run_fn(src, "map_filt", vec![Value::Record(m)]);
        match result {
            Value::Record(out) => {
                assert!(!out.contains_key("a"));
                assert!(out.contains_key("b"));
                assert!(out.contains_key("c"));
            }
            _ => panic!("expected Record/Map"),
        }
    }

    // F-8b: Multi-param closure |x, y| works with List.map (flat function)
    #[test]
    fn multi_param_closure_map() {
        // |x, y| desugars to a flat 2-arg fn; List.fold accumulates with curried lambda
        let src = r#"
fn fold_add(xs: List<Int>) -> Int {
    List.fold(xs, 0, |acc, x| acc + x)
}
"#;
        let xs = Value::List(vec![Value::Int(1), Value::Int(2), Value::Int(3)]);
        let result = run_fn(src, "fold_add", vec![xs]);
        match result {
            Value::Int(n) => assert_eq!(n, 6),
            _ => panic!("expected Int"),
        }
    }

    // F-9: Map.merge_with — merge two maps, combining shared keys
    #[test]
    fn map_merge_with_basic() {
        let src = r#"
fn map_merge(m1: Map<String, Int>, m2: Map<String, Int>) -> Map<String, Int> {
    Map.merge_with(|a| |b| a + b, m1, m2)
}
"#;
        let mut m1 = std::collections::HashMap::new();
        m1.insert("x".to_string(), Value::Int(10));
        m1.insert("y".to_string(), Value::Int(5));
        let mut m2 = std::collections::HashMap::new();
        m2.insert("x".to_string(), Value::Int(3));
        m2.insert("z".to_string(), Value::Int(7));
        let result = run_fn(src, "map_merge", vec![Value::Record(m1), Value::Record(m2)]);
        match result {
            Value::Record(out) => {
                // x: 10+3=13
                assert_eq!(out.get("x"), Some(&Value::Int(13)));
                // y only in m1
                assert_eq!(out.get("y"), Some(&Value::Int(5)));
                // z only in m2
                assert_eq!(out.get("z"), Some(&Value::Int(7)));
            }
            _ => panic!("expected Record/Map"),
        }
    }
}

// ── stdlib_v91_extra_tests (v9.1.0) ───────────────────────────────────────────
// 追加テスト: List / String / Option stdlib 関数の動作確認
#[cfg(test)]
mod stdlib_v91_extra_tests {
    use crate::backend::vm::VM;
    use crate::backend::artifact::FvcArtifact;
    use crate::backend::codegen::codegen_program;
    use crate::frontend::parser::Parser;
    use crate::middle::compiler::compile_program;
    use crate::value::Value;

    fn run_fn(src: &str, fname: &str, args: Vec<Value>) -> Value {
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let ir = compile_program(&prog);
        let artifact: FvcArtifact = codegen_program(&ir);
        let fn_idx = artifact.fn_idx_by_name(fname).expect("fn not found");
        VM::run(&artifact, fn_idx, args).expect("VM error")
    }

    // G-1: List.sum — 整数リストの合計
    #[test]
    fn list_sum_basic() {
        let src = r#"fn do_sum(xs: List<Int>) -> Int { List.sum(xs) }"#;
        let xs = Value::List(vec![Value::Int(1), Value::Int(2), Value::Int(3), Value::Int(4)]);
        assert_eq!(run_fn(src, "do_sum", vec![xs]), Value::Int(10));
    }

    // G-2: List.sum — 空リストは 0
    #[test]
    fn list_sum_empty() {
        let src = r#"fn do_sum(xs: List<Int>) -> Int { List.sum(xs) }"#;
        assert_eq!(run_fn(src, "do_sum", vec![Value::List(vec![])]), Value::Int(0));
    }

    // G-3: List.min — 最小値を返す
    #[test]
    fn list_min_basic() {
        let src = r#"fn do_min(xs: List<Int>) -> Option<Int> { List.min(xs) }"#;
        let xs = Value::List(vec![Value::Int(3), Value::Int(1), Value::Int(4), Value::Int(1), Value::Int(5)]);
        let result = run_fn(src, "do_min", vec![xs]);
        match result {
            Value::Variant(tag, payload) => {
                assert_eq!(tag, "some");
                assert_eq!(payload.map(|v| *v), Some(Value::Int(1)));
            }
            _ => panic!("expected some(1), got {:?}", result),
        }
    }

    // G-4: List.max — 最大値を返す
    #[test]
    fn list_max_basic() {
        let src = r#"fn do_max(xs: List<Int>) -> Option<Int> { List.max(xs) }"#;
        let xs = Value::List(vec![Value::Int(3), Value::Int(1), Value::Int(5), Value::Int(2)]);
        let result = run_fn(src, "do_max", vec![xs]);
        match result {
            Value::Variant(tag, payload) => {
                assert_eq!(tag, "some");
                assert_eq!(payload.map(|v| *v), Some(Value::Int(5)));
            }
            _ => panic!("expected some(5), got {:?}", result),
        }
    }

    // G-5: List.unique — 順序保持で重複除去
    #[test]
    fn list_unique_dedup() {
        let src = r#"fn do_unique(xs: List<Int>) -> List<Int> { List.unique(xs) }"#;
        let xs = Value::List(vec![
            Value::Int(1), Value::Int(2), Value::Int(1), Value::Int(3), Value::Int(2),
        ]);
        let result = run_fn(src, "do_unique", vec![xs]);
        match result {
            Value::List(items) => {
                let ints: Vec<i64> = items.into_iter().map(|v| match v {
                    Value::Int(n) => n,
                    _ => panic!(),
                }).collect();
                assert_eq!(ints, vec![1, 2, 3]);
            }
            _ => panic!("expected List"),
        }
    }

    // G-6: List.take_while — 条件を満たす間だけ取得
    #[test]
    fn list_take_while_basic() {
        let src = r#"fn do_tw(xs: List<Int>) -> List<Int> { List.take_while(xs, |x| x < 4) }"#;
        let xs = Value::List(vec![Value::Int(1), Value::Int(2), Value::Int(3), Value::Int(4), Value::Int(5)]);
        let result = run_fn(src, "do_tw", vec![xs]);
        match result {
            Value::List(items) => {
                let ints: Vec<i64> = items.into_iter().map(|v| match v { Value::Int(n) => n, _ => panic!() }).collect();
                assert_eq!(ints, vec![1, 2, 3]);
            }
            _ => panic!("expected List"),
        }
    }

    // G-7: List.drop_while — 条件を満たす間スキップ
    #[test]
    fn list_drop_while_basic() {
        let src = r#"fn do_dw(xs: List<Int>) -> List<Int> { List.drop_while(xs, |x| x < 3) }"#;
        let xs = Value::List(vec![Value::Int(1), Value::Int(2), Value::Int(3), Value::Int(4)]);
        let result = run_fn(src, "do_dw", vec![xs]);
        match result {
            Value::List(items) => {
                let ints: Vec<i64> = items.into_iter().map(|v| match v { Value::Int(n) => n, _ => panic!() }).collect();
                assert_eq!(ints, vec![3, 4]);
            }
            _ => panic!("expected List"),
        }
    }

    // G-8: List.flat_map — map して concat
    #[test]
    fn list_flat_map_basic() {
        let src = r#"fn do_fm(xs: List<Int>) -> List<Int> { List.flat_map(xs, |x| List.push(List.push(List.empty(), x), x * 10)) }"#;
        let xs = Value::List(vec![Value::Int(1), Value::Int(2)]);
        let result = run_fn(src, "do_fm", vec![xs]);
        match result {
            Value::List(items) => {
                let ints: Vec<i64> = items.into_iter().map(|v| match v { Value::Int(n) => n, _ => panic!() }).collect();
                assert_eq!(ints, vec![1, 10, 2, 20]);
            }
            _ => panic!("expected List"),
        }
    }

    // G-9: String.pad_left — 左パディング
    #[test]
    fn string_pad_left_basic() {
        let src = r#"fn do_pl(s: String) -> String { String.pad_left(s, 6, "0") }"#;
        let result = run_fn(src, "do_pl", vec![Value::Str("42".to_string())]);
        assert_eq!(result, Value::Str("000042".to_string()));
    }

    // G-10: String.pad_right — 右パディング
    #[test]
    fn string_pad_right_basic() {
        let src = r#"fn do_pr(s: String) -> String { String.pad_right(s, 5, "-") }"#;
        let result = run_fn(src, "do_pr", vec![Value::Str("hi".to_string())]);
        assert_eq!(result, Value::Str("hi---".to_string()));
    }

    // G-11: String.repeat — 文字列を繰り返す
    #[test]
    fn string_repeat_basic() {
        let src = r#"fn do_rep(s: String) -> String { String.repeat(s, 3) }"#;
        let result = run_fn(src, "do_rep", vec![Value::Str("ab".to_string())]);
        assert_eq!(result, Value::Str("ababab".to_string()));
    }

    // G-12: Option.map — Some 値を変換
    #[test]
    fn option_map_some() {
        let src = r#"fn do_om(o: Option<Int>) -> Option<Int> { Option.map(o, |x| x * 2) }"#;
        let opt = Value::Variant("some".to_string(), Some(Box::new(Value::Int(5))));
        let result = run_fn(src, "do_om", vec![opt]);
        match result {
            Value::Variant(tag, payload) => {
                assert_eq!(tag, "some");
                assert_eq!(payload.map(|v| *v), Some(Value::Int(10)));
            }
            _ => panic!("expected some(10)"),
        }
    }

    // G-13: Option.unwrap_or — None のときデフォルト値
    #[test]
    fn option_unwrap_or_none() {
        let src = r#"fn do_uo(o: Option<Int>) -> Int { Option.unwrap_or(o, 99) }"#;
        let none = Value::Variant("none".to_string(), None);
        assert_eq!(run_fn(src, "do_uo", vec![none]), Value::Int(99));
    }
}

// ── rvm_tests (v9.1.0) ────────────────────────────────────────────────────────
// rvm 独立バイナリの動作確認
#[cfg(test)]
// ── v9.2.0: fav fmt / pretty printer tests ────────────────────────────────────
#[cfg(test)]
mod fmt_tests {
    use crate::compiler_fav_runner::fmt_source_str;

    // D-1: シンプルな fn 定義の整形が期待通りであること
    #[test]
    fn fmt_simple_fn() {
        let src = "fn add(x: Int, y: Int) -> Int {\n    x + y\n}";
        let result = fmt_source_str(src).expect("fmt_source_str failed");
        // Should be parseable and formatted consistently
        assert!(result.contains("fn add(x: Int, y: Int) -> Int {"));
        assert!(result.contains("x + y"));
        assert!(!result.is_empty());
    }

    // D-2: 冪等性テスト — 2 回適用しても結果が変わらない
    #[test]
    fn fmt_idempotent() {
        let src = "fn double(n: Int) -> Int {\n  n * 2\n}\nfn inc(n: Int) -> Int {\n    n + 1\n}";
        let first = fmt_source_str(src).expect("first fmt failed");
        let second = fmt_source_str(&first).expect("second fmt failed");
        assert_eq!(first, second, "formatter is not idempotent");
    }

    // D-3: stage / seq 定義の整形テスト
    #[test]
    fn fmt_stage_and_seq() {
        let src = "stage Double: Int -> Int = |n| n * 2\nstage AddOne: Int -> Int = |n| n + 1\nseq Pipeline = Double |> AddOne";
        let result = fmt_source_str(src).expect("fmt_source_str failed");
        assert!(result.contains("stage Double: Int -> Int = |n| n * 2"));
        assert!(result.contains("seq Pipeline = Double |> AddOne"));
        // Idempotency
        let second = fmt_source_str(&result).expect("second fmt failed");
        assert_eq!(result, second, "stage/seq fmt not idempotent");
    }

    // D-4: match 式を含む fn 定義の整形
    #[test]
    fn fmt_match_expr() {
        let src = "fn safe_div(x: Int, y: Int) -> Int {\n    if y == 0 {\n        0\n    } else {\n        x + y\n    }\n}";
        let result = fmt_source_str(src).expect("fmt_source_str failed");
        assert!(result.contains("fn safe_div(x: Int, y: Int) -> Int {"));
        // Idempotency
        let second = fmt_source_str(&result).expect("second fmt failed");
        assert_eq!(result, second, "match fmt not idempotent");
    }

    // D-5: bind 式を含む fn 定義の整形
    #[test]
    fn fmt_bind_expr() {
        let src = "fn greet(name: String) -> String {\n    bind greeting <- \"Hello, \"\n    greeting + name\n}";
        let result = fmt_source_str(src).expect("fmt_source_str failed");
        assert!(result.contains("fn greet(name: String) -> String {"));
        assert!(result.contains("bind greeting <-"));
        // Idempotency
        let second = fmt_source_str(&result).expect("second fmt failed");
        assert_eq!(result, second, "bind fmt not idempotent");
    }
}

#[cfg(test)]
mod lint_tests {
    use crate::compiler_fav_runner::lint_source_str;

    // E-1: W001 — stage が Unit を返すがエフェクトなし
    #[test]
    fn lint_w001_effectless_sink() {
        let src = "stage Noop: String -> Unit = |s| ()";
        let output = lint_source_str(src).expect("lint_source_str failed");
        assert!(output.contains("W001"), "expected W001 in: {}", output);
    }

    // E-2: W002 — seq の最終 stage にエフェクトなし
    #[test]
    fn lint_w002_no_write_in_seq() {
        let src = "stage Pure: Int -> Int = |x| x\nseq S = Pure";
        let output = lint_source_str(src).expect("lint_source_str failed");
        assert!(output.contains("W002"), "expected W002 in: {}", output);
    }

    // E-3: W003 — 束縛変数が未使用
    #[test]
    fn lint_w003_unused_binding() {
        let src = "fn f() -> Int {\n    bind x <- 42\n    99\n}";
        let output = lint_source_str(src).expect("lint_source_str failed");
        assert!(output.contains("W003"), "expected W003 in: {}", output);
    }

    // E-4: W005 — match の腕が _ のみ
    #[test]
    fn lint_w005_wildcard_only() {
        let src = "fn f(x: Int) -> String {\n    match x {\n        _ => \"ok\"\n    }\n}";
        let output = lint_source_str(src).expect("lint_source_str failed");
        assert!(output.contains("W005"), "expected W005 in: {}", output);
    }

    // E-5: 警告なしのソースでは空文字列が返る
    #[test]
    fn lint_clean_source_no_warnings() {
        let src = "fn add(a: Int, b: Int) -> Int {\n    a + b\n}";
        let output = lint_source_str(src).expect("lint_source_str failed");
        assert_eq!(output.trim(), "", "expected no warnings, got: {}", output);
    }

    // E-6: W001 は abstract stage では発火しない
    #[test]
    fn lint_w001_abstract_stage_no_warn() {
        let src = "abstract stage Sink: String -> Unit";
        let output = lint_source_str(src).expect("lint_source_str failed");
        assert!(!output.contains("W001"), "W001 should not fire for abstract stage, got: {}", output);
    }

    // W004: fn の引数が 4 個以上で警告
    #[test]
    fn lint_w004_too_many_params() {
        let src = "fn big(a: Int, b: Int, c: Int, d: Int) -> Int { a + b + c + d }";
        let output = lint_source_str(src).expect("lint_source_str failed");
        assert!(output.contains("W004"), "expected W004 in: {}", output);
    }

    // W004: fn の引数が 3 個なら警告なし
    #[test]
    fn lint_w004_three_params_ok() {
        let src = "fn ok3(a: Int, b: Int, c: Int) -> Int { a + b + c }";
        let output = lint_source_str(src).expect("lint_source_str failed");
        assert!(!output.contains("W004"), "W004 should not fire for 3 params, got: {}", output);
    }
}

#[cfg(test)]
mod rvm_tests {
    // F-1: VM_VERSION 定数の値を確認
    #[test]
    fn rvm_version_constant() {
        assert_eq!(crate::backend::vm::VM_VERSION, "1.0.0");
    }

    // G-7: rvm が .fvc ファイルを正常に実行できる（compile_src_str_to_bytes → exec_fvc_file 経由）
    #[test]
    fn rvm_exec_fvc_file() {
        use crate::backend::artifact::FvcArtifact;
        use crate::backend::vm::VM;
        use crate::value::Value;

        // compile a simple program to .fvc bytes via compiler_fav_runner
        let src = "public fn main() -> Int { 6 * 7 }";
        let bytes = crate::compiler_fav_runner::compile_src_str_to_bytes(src)
            .expect("compile_src_str_to_bytes");

        // write bytes to a temp .fvc file
        let tmp = std::env::temp_dir().join("rvm_exec_test.fvc");
        std::fs::write(&tmp, &bytes).unwrap();

        // re-read and execute (same path as rvm's exec_fvc_file)
        let art = FvcArtifact::from_bytes(&bytes).expect("from_bytes");
        let idx = art.fn_idx_by_name("main").unwrap();
        let result = VM::run(&art, idx, vec![]).unwrap();
        assert_eq!(result, Value::Int(42));
    }
}

// ── v940_tests (v9.4.0) — json/gen builtins + csv I/O + W004 ─────────────────
#[cfg(test)]
mod v940_tests {
    use crate::backend::artifact::FvcArtifact;
    use crate::backend::codegen::codegen_program;
    use crate::backend::vm::VM;
    use crate::frontend::parser::Parser;
    use crate::middle::compiler::compile_program;
    use crate::value::Value;

    fn run_fn(src: &str, fname: &str, args: Vec<Value>) -> Value {
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let ir = compile_program(&prog);
        let artifact: FvcArtifact = codegen_program(&ir);
        let fn_idx = artifact.fn_idx_by_name(fname).expect("fn not found");
        VM::run(&artifact, fn_idx, args).expect("VM error")
    }

    // F-1: Json.pretty_raw — JSON 文字列を整形する
    #[test]
    fn json_pretty_raw_formats() {
        let src = r#"fn test_pretty(s: String) -> String { Json.pretty_raw(s) }"#;
        let result = run_fn(src, "test_pretty", vec![Value::Str("{\"a\":1,\"b\":2}".to_string())]);
        match result {
            Value::Str(s) => {
                assert!(s.contains('\n'), "pretty output should contain newlines: {}", s);
                assert!(s.contains("  "), "pretty output should contain indentation: {}", s);
            }
            other => panic!("expected Str, got {:?}", other),
        }
    }

    // F-2: Json.pretty_raw — invalid JSON はエラーを返す
    #[test]
    fn json_pretty_raw_invalid_json_errors() {
        let src = r#"
fn test_pretty_err(s: String) -> String {
    Json.pretty_raw(s)
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let ir = compile_program(&prog);
        let artifact: FvcArtifact = codegen_program(&ir);
        let fn_idx = artifact.fn_idx_by_name("test_pretty_err").expect("fn not found");
        let result = VM::run(&artifact, fn_idx, vec![Value::Str("not json".to_string())]);
        assert!(result.is_err(), "expected VM error on invalid JSON");
    }

    // F-3: Gen.uuid_raw — UUID v4 が 36 文字で返る
    #[test]
    fn gen_uuid_raw_returns_v4() {
        let src = r#"fn test_uuid() -> String { Gen.uuid_raw() }"#;
        let result = run_fn(src, "test_uuid", vec![]);
        match result {
            Value::Str(s) => {
                assert_eq!(s.len(), 36, "UUID v4 should be 36 chars: {}", s);
                let parts: Vec<&str> = s.split('-').collect();
                assert_eq!(parts.len(), 5, "UUID should have 5 hyphen-separated parts: {}", s);
            }
            other => panic!("expected Str, got {:?}", other),
        }
    }

    // F-4: Gen.uuid_v7_raw — UUID v7 が 36 文字で返る
    #[test]
    fn gen_uuid_v7_raw_returns_v7() {
        let src = r#"fn test_uuid_v7() -> String { Gen.uuid_v7_raw() }"#;
        let result = run_fn(src, "test_uuid_v7", vec![]);
        match result {
            Value::Str(s) => {
                assert_eq!(s.len(), 36, "UUID v7 should be 36 chars: {}", s);
                let parts: Vec<&str> = s.split('-').collect();
                assert_eq!(parts.len(), 5, "UUID should have 5 hyphen-separated parts: {}", s);
            }
            other => panic!("expected Str, got {:?}", other),
        }
    }

    // F-5: Gen.nano_id_raw — 指定した文字数で返る
    #[test]
    fn gen_nano_id_raw_correct_len() {
        let src = r#"fn test_nano(n: Int) -> String { Gen.nano_id_raw(n) }"#;
        let result = run_fn(src, "test_nano", vec![Value::Int(12)]);
        match result {
            Value::Str(s) => {
                assert_eq!(s.len(), 12, "nano_id(12) should be 12 chars: {}", s);
                assert!(
                    s.chars().all(|c| c.is_alphanumeric() || c == '_' || c == '-'),
                    "nano_id should only contain URL-safe chars: {}",
                    s
                );
            }
            other => panic!("expected Str, got {:?}", other),
        }
    }

    // F-6: Gen.uuid_raw — 2 回呼ぶと異なる値が返る（衝突確率は無視できる）
    #[test]
    fn gen_uuid_raw_unique() {
        let src = r#"fn test_uuid() -> String { Gen.uuid_raw() }"#;
        let a = match run_fn(src, "test_uuid", vec![]) {
            Value::Str(s) => s,
            other => panic!("expected Str, got {:?}", other),
        };
        let b = match run_fn(src, "test_uuid", vec![]) {
            Value::Str(s) => s,
            other => panic!("expected Str, got {:?}", other),
        };
        assert_ne!(a, b, "two uuid() calls should return different values");
    }

    // F-7: Csv.parse_raw + IO.write_file_raw — CSV ファイル書き込みと読み込み
    #[test]
    fn csv_write_and_read_via_builtins() {
        use tempfile::NamedTempFile;
        let tmp = NamedTempFile::new().unwrap();
        let path = tmp.path().to_str().unwrap().to_string();

        // write CSV
        let src_write = r#"
fn test_write(path: String, content: String) -> Unit {
    match IO.write_file_raw(path, content) {
        Ok(_) => ()
        Err(e) => ()
    }
}
"#;
        let csv_content = "id,name\n1,Alice\n2,Bob\n";
        run_fn(src_write, "test_write", vec![
            Value::Str(path.clone()),
            Value::Str(csv_content.to_string()),
        ]);

        // read back and parse
        let src_read = r#"
fn test_read(path: String) -> String {
    match IO.read_file_raw(path) {
        Ok(s) => s
        Err(e) => ""
    }
}
"#;
        let result = run_fn(src_read, "test_read", vec![Value::Str(path)]);
        match result {
            Value::Str(s) => {
                assert!(s.contains("Alice"), "CSV content should contain Alice: {}", s);
                assert!(s.contains("Bob"), "CSV content should contain Bob: {}", s);
            }
            other => panic!("expected Str, got {:?}", other),
        }
    }
}

// ── v960_tests (v9.6.0) — LLM Rune / !Llm effect ────────────────────────────
#[cfg(test)]
mod v960_tests {
    use super::tests::run_fav_test_file_with_runes;
    use crate::lineage::lineage_analysis;

    #[test]
    fn llm_effect_llm_accepted() {
        // !Llm 宣言関数内で Llm.* 呼び出しが E0003 を出さないこと
        let src = r#"
public fn ask(prompt: String) -> Result<String, String> !Llm {
    Llm.complete_raw(prompt)
}
"#;
        let errors = super::check_source_str(src);
        let e0003: Vec<_> = errors.iter().filter(|e| e.code == "E0003").collect();
        assert!(e0003.is_empty(), "unexpected E0003 with !Llm: {:?}", e0003);
    }

    #[test]
    fn llm_effect_missing_errors() {
        // !Llm 未宣言で Llm.complete_raw を呼ぶと E0003
        let src = r#"
public fn ask(prompt: String) -> Result<String, String> {
    Llm.complete_raw(prompt)
}
"#;
        let errors = super::check_source_str(src);
        let has_e0003 = errors.iter().any(|e| e.code == "E0003");
        assert!(has_e0003, "expected E0003 for missing !Llm effect, got: {:?}", errors);
    }

    #[test]
    fn lineage_llm_effect_in_sources() {
        use crate::frontend::parser::Parser;
        let src = r#"
stage AskLlm: String -> String !Llm = |prompt| {
    match Llm.complete_raw(prompt) {
        Ok(text) => text
        Err(_) => ""
    }
}
seq Pipeline = AskLlm
"#;
        let prog = Parser::parse_str(src, "test").unwrap();
        let report = lineage_analysis(&prog);
        let text = crate::lineage::render_lineage_text(&report, "test");
        // v13.9.0: lineage now shows capability kind and name instead of effect strings
        assert!(
            text.contains("AskLlm") && (text.contains("io") || text.contains("transform") || text.contains("!Llm") || report.transformations.iter().any(|e| e.name == "AskLlm")),
            "expected AskLlm in lineage: {}",
            text
        );
    }

    #[test]
    fn llm_rune_test_file_passes() {
        // API キーを確実に unset してテスト（no_key_is_err アサーションが通る）
        unsafe {
            std::env::remove_var("ANTHROPIC_API_KEY");
            std::env::remove_var("OPENAI_API_KEY");
        }
        let results = run_fav_test_file_with_runes("runes/llm/llm.test.fav");
        let failures: Vec<_> = results.iter().filter(|(_, ok, _)| !ok).collect();
        assert!(failures.is_empty(), "llm.test.fav failures: {:?}", failures);
    }
}

