// ── v970_tests (v9.7.0) — T?/??/expr? + nominal wrapper types ────────────────
#[cfg(test)]
mod v970_tests {
    use crate::backend::artifact::FvcArtifact;
    use crate::backend::vm::VM;
    use crate::value::Value;

    fn compile_and_run(name: &str, src: &str) -> Value {
        let filename = format!("fav_v970_{}.fav", name);
        let tmp = std::env::temp_dir().join(filename);
        std::fs::write(&tmp, src).expect("write tmp");
        let path = tmp.to_str().expect("utf8 path");
        let bytes = crate::compiler_fav_runner::compile_file_to_bytes(path)
            .unwrap_or_else(|e| panic!("compiler.fav error: {}", e));
        let artifact = FvcArtifact::from_bytes(&bytes)
            .unwrap_or_else(|e| panic!("artifact error: {:?}", e));
        let fn_idx = artifact.fn_idx_by_name("main").expect("main not found");
        VM::run(&artifact, fn_idx, vec![]).expect("VM::run failed")
    }

    // ── T? / ?? operator tests ─────────────────────────────────────────────────

    #[test]
    fn null_coalesce_some_returns_inner() {
        // Option.some(42) ?? 0 => 42
        let result = compile_and_run(
            "nc_some",
            r#"public fn main() -> Int { Option.some(42) ?? 0 }"#,
        );
        assert_eq!(result, Value::Int(42));
    }

    #[test]
    fn null_coalesce_none_returns_default() {
        // Option.none() ?? 99 => 99
        let result = compile_and_run(
            "nc_none",
            r#"public fn main() -> Int { Option.none() ?? 99 }"#,
        );
        assert_eq!(result, Value::Int(99));
    }

    #[test]
    fn type_option_postfix_t_question() {
        // T? is equivalent to Option<T> — fn returns Option<Int>
        let result = compile_and_run(
            "tq",
            r#"fn wrap(x: Int) -> Int? { Option.some(x) }
               public fn main() -> Int { wrap(7) ?? 0 }"#,
        );
        assert_eq!(result, Value::Int(7));
    }

    #[test]
    fn expr_question_unwraps_ok() {
        // expr? unwraps the Ok value directly
        let result = compile_and_run(
            "exprq_ok",
            r#"fn safe_double(n: Int) -> Result<Int, String> {
                   Result.ok(n * 2)
               }
               public fn main() -> Int {
                   safe_double(5)?
               }"#,
        );
        assert_eq!(result, Value::Int(10));
    }

    #[test]
    fn expr_question_propagates_err() {
        // expr? in an Err case: the Err is preserved
        let result = compile_and_run(
            "exprq_err",
            r#"fn fail() -> Result<Int, String> { Result.err("oops") }
               public fn main() -> String {
                   match fail()? {
                       Ok(_) => "ok"
                       Err(e) => e
                   }
               }"#,
        );
        assert_eq!(result, Value::Str("oops".to_string()));
    }

    // ── Nominal wrapper type tests ─────────────────────────────────────────────

    #[test]
    fn wrapper_type_constructor_and_match() {
        // type UserId(Int) — constructor + pattern extraction
        let result = compile_and_run(
            "wrapper_ctor",
            r#"type UserId(Int)
               public fn main() -> Int {
                   match UserId(42) {
                       UserId(n) => n
                   }
               }"#,
        );
        assert_eq!(result, Value::Int(42));
    }

    #[test]
    fn wrapper_type_fn_param_and_return() {
        // pass wrapper as function parameter, extract inside
        let result = compile_and_run(
            "wrapper_fn",
            r#"type EmailAddr(String)
               fn get_addr(e: EmailAddr) -> String {
                   match e { EmailAddr(s) => s }
               }
               public fn main() -> String {
                   get_addr(EmailAddr("user@example.com"))
               }"#,
        );
        assert_eq!(result, Value::Str("user@example.com".to_string()));
    }

    #[test]
    fn wrapper_type_in_option() {
        // Option<WrapperType> — wrap and unwrap
        let result = compile_and_run(
            "wrapper_opt",
            r#"type Score(Int)
               fn try_score(n: Int) -> Option<Score> {
                   if n > 0 { Option.some(Score(n)) } else { Option.none() }
               }
               public fn main() -> Int {
                   match try_score(100) {
                       Some(Score(v)) => v
                       None => 0
                   }
               }"#,
        );
        assert_eq!(result, Value::Int(100));
    }

    // ── checker.fav type-checks wrapper types without error ───────────────────

    #[test]
    fn wrapper_type_checker_no_error() {
        let src = r#"type UserId(Int)
fn make_user(n: Int) -> UserId { UserId(n) }
public fn main() -> Int { 1 }
"#;
        let errors = super::check_source_str(src);
        let has_errors = !errors.is_empty();
        assert!(!has_errors, "unexpected errors for wrapper type: {:?}", errors);
    }
}

// ── v975_tests (v9.7.5) — where validator + with parsing + E0013 ─────────────
#[cfg(test)]
mod v975_tests {
    use crate::backend::artifact::FvcArtifact;
    use crate::backend::vm::VM;
    use crate::value::Value;

    fn compile_and_run(name: &str, src: &str) -> Value {
        let filename = format!("fav_v975_{}.fav", name);
        let tmp = std::env::temp_dir().join(filename);
        std::fs::write(&tmp, src).expect("write tmp");
        let path = tmp.to_str().expect("utf8 path");
        let bytes = crate::compiler_fav_runner::compile_file_to_bytes(path)
            .unwrap_or_else(|e| panic!("compiler.fav error: {}", e));
        let artifact = FvcArtifact::from_bytes(&bytes)
            .unwrap_or_else(|e| panic!("artifact error: {:?}", e));
        let fn_idx = artifact.fn_idx_by_name("main").expect("main not found");
        VM::run(&artifact, fn_idx, vec![]).expect("VM::run failed")
    }

    #[test]
    fn where_validator_ok() {
        let result = compile_and_run(
            "where_ok",
            r#"type Percent(Float) where |v| v >= 0.0 && v <= 100.0
public fn main() -> String {
    match Percent(50.0) {
        Ok(_) => "ok"
        Err(e) => e
    }
}"#,
        );
        assert_eq!(result, Value::Str("ok".to_string()));
    }

    #[test]
    fn where_validator_err() {
        let result = compile_and_run(
            "where_err",
            r#"type Percent(Float) where |v| v >= 0.0 && v <= 100.0
public fn main() -> String {
    match Percent(150.0) {
        Ok(_) => "ok"
        Err(e) => e
    }
}"#,
        );
        assert_eq!(result, Value::Str("Percent: validation failed".to_string()));
    }

    #[test]
    fn where_validator_in_fn() {
        let result = compile_and_run(
            "where_fn",
            r#"type Percent(Float) where |v| v >= 0.0 && v <= 100.0
fn apply_discount(price: Float, pct: Float) -> String {
    match Percent(pct) {
        Err(e) => e
        Ok(p)  => Float.to_string(price * p / 100.0)
    }
}
public fn main() -> String {
    apply_discount(1000.0, 20.0)
}"#,
        );
        assert_eq!(result, Value::Str("200.0".to_string()));
    }

    #[test]
    fn with_clause_parses_ok() {
        // type UserId(Int) with Serialize — should parse without error, constructor works as before
        let result = compile_and_run(
            "with_parse",
            r#"type UserId(Int) with Serialize
public fn main() -> Int {
    match UserId(42) {
        UserId(n) => n
    }
}"#,
        );
        assert_eq!(result, Value::Int(42));
    }

    #[test]
    fn e0013_expr_question_on_option() {
        // Option.some(42)? should produce E0013 from checker.fav
        let src = r#"public fn main() -> Int { Option.some(42)? }"#;
        let errors = super::check_source_str(src);
        let has_e0013 = errors.iter().any(|e| {
            let msg = format!("{:?}", e);
            msg.contains("E0013")
        });
        assert!(has_e0013, "expected E0013 error, got: {:?}", errors);
    }

    #[test]
    fn where_validator_combined_with_and() {
        let src_ok = r#"type Username(String) where |s| String.length(s) > 0 && String.length(s) <= 5
public fn main() -> String {
    match Username("hi") {
        Ok(_) => "ok"
        Err(e) => e
    }
}"#;
        let src_err = r#"type Username(String) where |s| String.length(s) > 0 && String.length(s) <= 5
public fn main() -> String {
    match Username("") {
        Ok(_) => "ok"
        Err(e) => e
    }
}"#;
        assert_eq!(compile_and_run("username_ok", src_ok), Value::Str("ok".to_string()));
        assert_eq!(compile_and_run("username_err", src_err), Value::Str("Username: validation failed".to_string()));
    }
}

// ── v9100_tests (v9.10.0) — fav repl ────────────────────────────────────────
#[cfg(test)]
mod v9100_tests {
    use super::*;

    #[test]
    fn repl_build_eval_source_wraps_expr() {
        let session = ReplSession::new();
        let src = build_eval_source(&session, "1 + 2");
        assert!(src.contains("Debug.show_raw(1 + 2)"), "expected Debug.show_raw wrapper, got: {}", src);
        assert!(src.contains("fn main()"), "expected fn main(), got: {}", src);
    }

    #[test]
    fn repl_definition_accumulates() {
        let mut session = ReplSession::new();
        handle_definition("fn double(x: Int) -> Int { x * 2 }", &mut session);
        assert!(session.def_names.contains(&"double".to_string()), "expected 'double' in def_names");
        assert!(session.definitions.contains("fn double"), "expected definition in session.definitions");
        // Expression using the accumulated definition should compile
        let src = build_eval_source(&session, "double(21)");
        let result = crate::compiler_fav_runner::compile_src_str_to_bytes(&src);
        assert!(result.is_ok(), "expression using accumulated definition should compile: {:?}", result);
    }

    #[test]
    fn repl_error_recovery_on_bad_expr() {
        let mut session = ReplSession::new();
        // A definition with a type error should NOT be added to the session
        let before = session.definitions.clone();
        handle_definition("fn bad() -> Int { \"not an int\" }", &mut session);
        assert_eq!(session.definitions, before, "bad definition should not be added to session");
    }
}

// ── v990_tests (v9.9.0) — fav profile: stage timing + fav watch primitives ───
#[cfg(test)]
mod v990_tests {
    use crate::backend::vm::{clear_profile_records, take_profile_dump_json};
    use crate::compiler_fav_runner::compile_profiled_str;

    fn compile_and_run_profiled(src: &str) {
        let bytes = compile_profiled_str(src)
            .unwrap_or_else(|e| panic!("compile_profiled_str error: {}", e));
        let artifact = crate::backend::artifact::FvcArtifact::from_bytes(&bytes)
            .unwrap_or_else(|e| panic!("from_bytes error: {:?}", e));
        let main_idx = artifact.fn_idx_by_name("main").expect("main not found");
        clear_profile_records();
        crate::backend::vm::VM::run(&artifact, main_idx, vec![])
            .unwrap_or_else(|e| panic!("VM run error: {}", e.message));
    }

    #[test]
    fn profile_stage_names_collected() {
        // A program with two stages: verify compile_profiled_str succeeds
        let src = r#"
public stage double: Int -> Int = |x| x * 2
public stage inc:    Int -> Int = |x| x + 1
public fn main() -> Int { inc(double(3)) }
"#;
        let bytes = compile_profiled_str(src)
            .unwrap_or_else(|e| panic!("compile_profiled_str error: {}", e));
        assert!(!bytes.is_empty(), "expected non-empty bytecode");
    }

    #[test]
    fn profile_records_populated_after_run() {
        let src = r#"
public stage add_one: Int -> Int = |x| x + 1
public fn main() -> Int { add_one(41) }
"#;
        compile_and_run_profiled(src);
        let json = take_profile_dump_json();
        assert!(json.contains("\"add_one\""), "expected 'add_one' in profile dump:\n{}", json);
    }

    #[test]
    fn profile_no_overhead_normal_compile() {
        // compile_profiled_str output differs from normal compile_bytes_from_src
        // because instrumentation is injected
        let src = r#"
public stage noop: Int -> Int = |x| x
public fn main() -> Int { noop(1) }
"#;
        let profiled = compile_profiled_str(src)
            .unwrap_or_else(|e| panic!("compile_profiled_str: {}", e));
        let normal = crate::compiler_fav_runner::compile_src_str_to_bytes(src)
            .unwrap_or_else(|e| panic!("compile_src_str_to_bytes: {}", e));
        // Profiled bytecode should be LARGER due to injected timing calls
        assert!(
            profiled.len() > normal.len(),
            "profiled bytecode ({} bytes) should be larger than normal ({} bytes)",
            profiled.len(),
            normal.len()
        );
    }
}

// ── v980_tests (v9.8.0) — fav doc: /// doc comments → Markdown ───────────────
#[cfg(test)]
mod v980_tests {
    fn doc_source(src: &str) -> String {
        crate::compiler_fav_runner::doc_source_str(src)
            .unwrap_or_else(|e| panic!("doc_source_str error: {}", e))
    }

    #[test]
    fn doc_fn_no_comment() {
        let src = r#"public fn add(a: Int, b: Int) -> Int { a + b }"#;
        let md = doc_source(src);
        assert!(md.contains("### add"), "expected '### add' in:\n{}", md);
        assert!(md.contains("fn add(a: Int, b: Int) -> Int"), "expected sig in:\n{}", md);
    }

    #[test]
    fn doc_fn_with_comment() {
        let src = "/// Adds two integers.\npublic fn add(a: Int, b: Int) -> Int { a + b }";
        let md = doc_source(src);
        assert!(md.contains("### add"), "expected '### add' in:\n{}", md);
        assert!(md.contains("Adds two integers."), "expected doc text in:\n{}", md);
    }

    #[test]
    fn doc_private_fn_excluded() {
        let src = r#"/// Private helper.
fn helper(x: Int) -> Int { x }
public fn main() -> Int { helper(1) }"#;
        let md = doc_source(src);
        assert!(!md.contains("helper"), "private fn should be excluded:\n{}", md);
        assert!(md.contains("### main"), "public fn should be included:\n{}", md);
    }

    #[test]
    fn doc_type_def() {
        let src = r#"/// A point in 2D space.
type Point = { x: Int  y: Int }
public fn origin() -> Int { 0 }"#;
        let md = doc_source(src);
        assert!(md.contains("### Point"), "expected type in:\n{}", md);
        assert!(md.contains("A point in 2D space."), "expected doc text in:\n{}", md);
    }

    #[test]
    fn doc_wrapper_def() {
        let src = r#"/// A valid percentage.
type Percent(Float) where |v| v >= 0.0 && v <= 100.0
public fn make() -> Int { 0 }"#;
        let md = doc_source(src);
        assert!(md.contains("### Percent"), "expected wrapper in:\n{}", md);
        assert!(md.contains("A valid percentage."), "expected doc text in:\n{}", md);
    }

    #[test]
    fn doc_stage_def() {
        let src = r#"/// Normalizes a float value.
public stage normalize: Float -> Float = |v| v / 100.0"#;
        let md = doc_source(src);
        assert!(md.contains("### normalize"), "expected stage in:\n{}", md);
        assert!(md.contains("Normalizes a float value."), "expected doc text in:\n{}", md);
    }

    #[test]
    fn doc_multiline_comment() {
        let src = "/// First line.\n/// Second line.\npublic fn f() -> Int { 0 }";
        let md = doc_source(src);
        assert!(md.contains("First line."), "expected first line in:\n{}", md);
        assert!(md.contains("Second line."), "expected second line in:\n{}", md);
    }

    #[test]
    fn doc_empty_file() {
        let md = doc_source("");
        // Empty file should produce empty or minimal output without error
        assert!(md.len() < 100, "expected minimal output for empty file:\n{}", md);
    }
}

// ── v9120_tests (v9.12.0) — interface/impl self-hosted + E0014/E0015 ─────────
#[cfg(test)]
mod v9120_tests {
    use crate::frontend::parser::Parser;

    fn check_with_checker_fav(src: &str, name: &str) -> Result<(), Vec<String>> {
        let tmp = std::env::temp_dir().join(format!("fav_v9120_{}.fav", name));
        std::fs::write(&tmp, src).unwrap();
        let path = tmp.to_str().unwrap().to_string();
        let source = std::fs::read_to_string(&path).unwrap();
        let program = Parser::parse_str(&source, &path).expect("parse error");
        let prog_vm = crate::middle::ast_lower_checker::lower_program(&program);
        crate::checker_fav_runner::run_checker_fav(prog_vm)
    }

    fn compile_src(src: &str) -> Result<Vec<u8>, String> {
        let tmp = std::env::temp_dir().join("fav_v9120_compile.fav");
        std::fs::write(&tmp, src).unwrap();
        crate::compiler_fav_runner::compile_file_to_bytes(tmp.to_str().unwrap())
    }

    // D-1a: interface keyword compiles without parse error in Favnir pipeline
    #[test]
    fn interface_keyword_does_not_cause_parse_error() {
        let src = r#"
interface Greetable {
    greet: (String) -> String
}
public fn main() -> String { "ok" }
"#;
        let result = compile_src(src);
        assert!(result.is_ok(), "interface keyword caused error: {:?}", result.err());
    }

    // D-1b: impl keyword compiles without parse error in Favnir pipeline
    #[test]
    fn impl_keyword_does_not_cause_parse_error() {
        let src = r#"
interface Greetable {
    greet: (String) -> String
}
type Name(String)
impl Greetable for Name {
    fn greet(n: Name) -> String { "hello" }
}
public fn main() -> String { "ok" }
"#;
        let result = compile_src(src);
        assert!(result.is_ok(), "impl keyword caused error: {:?}", result.err());
    }

    // D-1c: missing impl block for user-defined interface → E0014
    #[test]
    fn missing_impl_e0014_detected() {
        // type Order(String) with Validatable: wrapper + user-defined interface + no impl block
        let src = r#"
interface Validatable {
    validate: String -> Bool
}
type Order(String) with Validatable
public fn main() -> String { "ok" }
"#;
        let result = check_with_checker_fav(src, "e0014");
        assert!(result.is_err(), "expected E0014 error for missing impl");
        let msgs = result.unwrap_err();
        assert!(
            msgs.iter().any(|m| m.contains("E0014")),
            "expected E0014 in errors, got: {:?}", msgs
        );
    }

    // D-1d: undefined interface referenced with `with` → E0015
    #[test]
    fn undefined_interface_e0015_detected() {
        // type Order(String) with Validatable: no interface definition at all → E0015
        let src = r#"
type Order(String) with Validatable
public fn main() -> String { "ok" }
"#;
        let result = check_with_checker_fav(src, "e0015");
        assert!(result.is_err(), "expected E0015 error for undefined interface");
        let msgs = result.unwrap_err();
        assert!(
            msgs.iter().any(|m| m.contains("E0015")),
            "expected E0015 in errors, got: {:?}", msgs
        );
    }

    // D-1e: Rune definition jump — handle_rune_definition returns None for unknown namespace
    #[test]
    fn rune_definition_returns_none_for_unknown_namespace() {
        let result = crate::lsp::definition::handle_rune_definition(
            "unknown_ns.some_fn(",
            18,
            "/tmp/workspace",
        );
        assert!(result.is_none(), "expected None for unknown namespace");
    }

    // D-1f: handle_rune_definition recognizes http namespace structure
    #[test]
    fn rune_definition_recognizes_http_namespace() {
        // When file doesn't exist it returns None — just verify it doesn't panic and
        // attempts to look up only known rune namespaces
        let result = crate::lsp::definition::handle_rune_definition(
            "http.get(",
            8,
            "/nonexistent/workspace",
        );
        // None is expected since rune_modules don't exist at that path
        // but it should not panic — the namespace IS known so it attempts the file lookup
        // The test passes whether Some or None (just verifying no panic)
        let _ = result;
    }
}

// ── v9130_tests (v9.13.0) — par 並列 stage 実行 ────────────────────────────────
#[cfg(test)]
mod v9130_tests {
    use crate::frontend::parser::Parser;
    use crate::middle::compiler::compile_program;
    use crate::backend::codegen::codegen_program;
    use crate::backend::vm::VM;
    use crate::value::Value;

    fn check_with_checker_fav(src: &str, name: &str) -> Result<(), Vec<String>> {
        let tmp = std::env::temp_dir().join(format!("fav_v9130_{}.fav", name));
        std::fs::write(&tmp, src).unwrap();
        let path = tmp.to_str().unwrap().to_string();
        let source = std::fs::read_to_string(&path).unwrap();
        let program = Parser::parse_str(&source, &path).expect("parse error");
        let prog_vm = crate::middle::ast_lower_checker::lower_program(&program);
        crate::checker_fav_runner::run_checker_fav(prog_vm)
    }

    fn run_inline(src: &str) -> Value {
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let ir = compile_program(&prog);
        let artifact = codegen_program(&ir);
        let fn_idx = artifact.fn_idx_by_name("main").expect("main not found");
        VM::run(&artifact, fn_idx, vec![]).expect("run")
    }

    // F-1a: par step compiles and executes without panicking
    #[test]
    fn par_executes_in_parallel() {
        let src = r#"
stage Double: Int -> Int = |n| { n * 2 }
stage AddTen: Int -> Int = |n| { n + 10 }
stage SumList: List<Int> -> Int = |xs| { List.fold(xs, 0, |acc, x| acc + x) }
seq TestPar = par [Double, AddTen] |> SumList
public fn main() -> Int { TestPar(5) }
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let ir = compile_program(&prog);
        let artifact = codegen_program(&ir);
        let fn_idx = artifact.fn_idx_by_name("main").expect("main not found");
        let result = VM::run(&artifact, fn_idx, vec![]);
        assert!(result.is_ok(), "par execution failed: {:?}", result.err());
    }

    // F-1b: par [Double, AddTen] |> SumList with input 5 returns 25 (10+15)
    #[test]
    fn par_result_is_correct() {
        let src = r#"
stage Double: Int -> Int = |n| { n * 2 }
stage AddTen: Int -> Int = |n| { n + 10 }
stage SumList: List<Int> -> Int = |xs| { List.fold(xs, 0, |acc, x| acc + x) }
seq TestPar = par [Double, AddTen] |> SumList
public fn main() -> Int { TestPar(5) }
"#;
        let result = run_inline(src);
        assert_eq!(result, Value::Int(25), "expected 25 (10+15), got: {:?}", result);
    }

    // F-1c: par stages with mismatched input types → E0016
    #[test]
    fn par_input_type_mismatch_e0016() {
        // Source produces Int; StrStage expects String → mismatch
        let src = r#"
stage Source: Int -> Int = |n| { n }
stage IntStage: Int -> Int = |n| { n + 1 }
stage StrStage: String -> String = |s| { s }
stage MergeI: List<Int> -> Int = |xs| { 0 }
seq BadPar = Source |> par [IntStage, StrStage] |> MergeI
public fn main() -> String { "ok" }
"#;
        let result = check_with_checker_fav(src, "e0016");
        assert!(result.is_err(), "expected E0016 for type mismatch in par");
        let msgs = result.unwrap_err();
        assert!(
            msgs.iter().any(|m| m.contains("E0016")),
            "expected E0016 in errors, got: {:?}", msgs
        );
    }

    // F-1d: par step references undefined stage → E0017
    #[test]
    fn par_unknown_stage_e0017() {
        let src = r#"
stage Double: Int -> Int = |n| { n * 2 }
stage SumList: List<Int> -> Int = |xs| { 0 }
seq BadPar = par [Double, UndefinedStage] |> SumList
public fn main() -> String { "ok" }
"#;
        let result = check_with_checker_fav(src, "e0017");
        assert!(result.is_err(), "expected E0017 for undefined stage in par");
        let msgs = result.unwrap_err();
        assert!(
            msgs.iter().any(|m| m.contains("E0017")),
            "expected E0017 in errors, got: {:?}", msgs
        );
    }

    // F-1e: seq with par compiles without error (Rust pipeline)
    #[test]
    fn par_compiles_with_favnir_pipeline() {
        let src = r#"
stage Double: Int -> Int = |n| { n * 2 }
stage AddTen: Int -> Int = |n| { n + 10 }
stage Merge: List<Int> -> Int = |xs| { 0 }
seq TestPar = par [Double, AddTen] |> Merge
public fn main() -> Int { TestPar(3) }
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let ir = compile_program(&prog);
        let artifact = codegen_program(&ir);
        assert!(artifact.fn_idx_by_name("TestPar").is_some(), "TestPar not compiled");
    }

    // F-1f: checker.fav handles a valid program with par stages without error
    #[test]
    fn par_effects_detected_by_checker_fav() {
        let src = r#"
stage Double: Int -> Int = |n| { n * 2 }
stage AddTen: Int -> Int = |n| { n + 10 }
stage SumList: List<Int> -> Int = |xs| { 0 }
seq TestPar = par [Double, AddTen] |> SumList
public fn main() -> Int { TestPar(1) }
"#;
        let result = check_with_checker_fav(src, "par_valid");
        assert!(result.is_ok(), "checker.fav errored on valid par program: {:?}", result.err());
    }
}

// ── v10.0.0 tests ──────────────────────────────────────────────────────────────
#[cfg(test)]
mod v10_tests {
    use crate::frontend::parser::Parser;
    use crate::middle::compiler::compile_program;
    use crate::backend::codegen::codegen_program;
    use crate::backend::vm::VM;
    use crate::value::Value;
    use tempfile::TempDir;

    fn run_with_io(src: &str) -> Result<Value, String> {
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let ir = compile_program(&prog);
        let artifact = codegen_program(&ir);
        let fn_idx = artifact.fn_idx_by_name("main").expect("main not found");
        VM::run(&artifact, fn_idx, vec![]).map_err(|e| format!("{:?}", e))
    }

    // D-1a: IO.make_dir_raw creates directory and write_file_raw creates files
    #[test]
    fn fav_new_creates_project_structure() {
        let dir = TempDir::new().unwrap();
        let root = dir.path().to_str().unwrap().replace('\\', "/");
        let project = root.clone() + "/myproject";
        let src_dir = project.clone() + "/src";

        let src = format!(
            r#"
public fn main() -> Unit !IO {{
    bind r1 <- IO.make_dir_raw("{src_dir}")
    match r1 {{
        Err(e) => IO.println(e)
        Ok(_)  => {{
            bind r2 <- IO.write_file_raw("{project}/fav.toml", "[project]\nname = \"myproject\"\n")
            bind r3 <- IO.write_file_raw("{src_dir}/main.fav", "// hello\n")
            bind r4 <- IO.write_file_raw("{project}/.gitignore", "*.fvc\n")
            IO.println("done")
        }}
    }}
}}
"#
        );

        let result = run_with_io(&src);
        assert!(result.is_ok(), "run failed: {:?}", result.err());

        assert!(
            std::path::Path::new(&format!("{}/fav.toml", project)).exists(),
            "fav.toml missing"
        );
        assert!(
            std::path::Path::new(&format!("{}/src/main.fav", project)).exists(),
            "src/main.fav missing"
        );
        assert!(
            std::path::Path::new(&format!("{}/.gitignore", project)).exists(),
            ".gitignore missing"
        );
    }

    // D-1b: the template main.fav compiles and runs without error
    #[test]
    fn fav_new_generated_project_runs() {
        let template = r#"
type Order = { id: Int  item: String  amount: Float }

stage ParseOrder: String -> Order = |s| {
  Order { id: 1  item: s  amount: 0.0 }
}

stage FormatOrder: Order -> String = |o| {
  String.concat("Order: ", o.item)
}

seq ProcessOrder = ParseOrder |> FormatOrder

public fn main() -> String { ProcessOrder("Widget") }
"#;
        let prog = Parser::parse_str(template, "main.fav").expect("parse");
        let ir = compile_program(&prog);
        let artifact = codegen_program(&ir);
        let fn_idx = artifact.fn_idx_by_name("main").expect("main not found");
        let result = VM::run(&artifact, fn_idx, vec![]).expect("run failed");
        match result {
            Value::Str(s) => assert_eq!(s, "Order: Widget"),
            other => panic!("unexpected result: {:?}", other),
        }
    }
}

