// ── v12200_tests (v12.2.0) — W006 (bind _ Result) + W007 (deep match) ─────────

#[cfg(test)]
mod v12200_tests {
    use crate::compiler_fav_runner::lint_source_str;

    // ── W006 helpers ─────────────────────────────────────────────────────────

    fn get_w006_warnings(src: &str, name: &str) -> String {
        let tmp = std::env::temp_dir().join(format!("fav_w006_{}.fav", name));
        std::fs::write(&tmp, src).unwrap();
        let path = tmp.to_str().unwrap();
        let source = super::load_file(path);
        let program = crate::frontend::parser::Parser::parse_str(&source, path)
            .expect("parse error");
        let prog_vm = crate::middle::ast_lower_checker::lower_program(&program);
        crate::checker_fav_runner::run_checker_fav_full(prog_vm)
            .expect("unexpected type error")
    }

    // ── W006: bind _ で Result を捨てる ──────────────────────────────────────

    // W006-1: bind _ <- Postgres.execute_raw(...) → W006
    #[test]
    fn w006_bind_underscore_result() {
        let src = r#"fn f(x: String) -> String !Postgres {
    bind _ <- Postgres.execute_raw(x, x)
    x
}"#;
        let output = get_w006_warnings(src, "w006_1");
        assert!(output.contains("W006"), "expected W006 in: {}", output);
    }

    // W006-2: bind _ <- IO.println(...) → Unit → 警告なし
    #[test]
    fn w006_bind_underscore_unit() {
        let src = r#"fn f(x: String) -> String !IO {
    bind _ <- IO.println(x)
    x
}"#;
        let output = get_w006_warnings(src, "w006_2");
        assert!(!output.contains("W006"), "W006 should not fire for Unit: {}", output);
    }

    // W006-3: chain res <- Postgres.execute_raw(...) → エラー伝播するため警告なし
    #[test]
    fn w006_chain_underscore_ok() {
        let src = r#"fn f(x: String) -> String !Postgres {
    chain res <- Postgres.execute_raw(x, x)
    x
}"#;
        let output = get_w006_warnings(src, "w006_3");
        assert!(!output.contains("W006"), "W006 should not fire for chain _: {}", output);
    }

    // W006-4: explicit match は安全 → 警告なし
    #[test]
    fn w006_explicit_match_ok() {
        let src = r#"fn f(x: String) -> String !Postgres {
    match Postgres.execute_raw(x, x) {
        Ok(_) => x
        Err(e) => x
    }
}"#;
        let output = get_w006_warnings(src, "w006_4");
        assert!(!output.contains("W006"), "W006 should not fire for explicit match: {}", output);
    }

    // W006-5: allow = ["W006"] でフィルタ → 警告なし（Rust 側でフィルタ）
    #[test]
    fn w006_fav_toml_allow() {
        let src = r#"fn f(x: String) -> String !Postgres {
    bind _ <- Postgres.execute_raw(x, x)
    x
}"#;
        let output = get_w006_warnings(src, "w006_5");
        // Simulate fav.toml [lint] allow = ["W006"]
        let filtered: String = output
            .lines()
            .filter(|l| !l.starts_with("W006"))
            .collect::<Vec<_>>()
            .join("\n");
        assert!(!filtered.contains("W006"), "W006 should be suppressed by allow list");
    }

    // ── W007: 深い match ネスト ───────────────────────────────────────────────

    // W007-1: 2段ネスト → 警告なし
    #[test]
    fn w007_depth_2_ok() {
        let src = r#"fn f(x: Int) -> Int {
    match x {
        _ => match x { _ => x }
    }
}"#;
        let output = lint_source_str(src).expect("lint failed");
        assert!(!output.contains("W007"), "W007 should not fire for depth 2: {}", output);
    }

    // W007-2: 3段ネスト → W007
    #[test]
    fn w007_depth_3_warn() {
        let src = r#"fn f(x: Int) -> Int {
    match x {
        _ => match x {
            _ => match x { _ => x }
        }
    }
}"#;
        let output = lint_source_str(src).expect("lint failed");
        assert!(output.contains("W007"), "expected W007 for depth 3: {}", output);
    }

    // W007-3: 4段ネスト → W007
    #[test]
    fn w007_depth_4_warn() {
        let src = r#"fn f(x: Int) -> Int {
    match x {
        _ => match x {
            _ => match x {
                _ => match x { _ => x }
            }
        }
    }
}"#;
        let output = lint_source_str(src).expect("lint failed");
        assert!(output.contains("W007"), "expected W007 for depth 4: {}", output);
    }

    // W007-4: ヘルパー関数に切り出し → 警告なし
    #[test]
    fn w007_helper_fn_ok() {
        let src = r#"fn inner(x: Int) -> Int {
    match x { _ => x }
}
fn f(x: Int) -> Int {
    match x {
        _ => match x { _ => inner(x) }
    }
}"#;
        let output = lint_source_str(src).expect("lint failed");
        assert!(!output.contains("W007"), "W007 should not fire when helper used: {}", output);
    }

    // W007-5: allow = ["W007"] でフィルタ → 警告なし
    #[test]
    fn w007_fav_toml_allow() {
        let src = r#"fn f(x: Int) -> Int {
    match x {
        _ => match x {
            _ => match x { _ => x }
        }
    }
}"#;
        let output = lint_source_str(src).expect("lint failed");
        // Simulate fav.toml [lint] allow = ["W007"]
        let filtered: String = output
            .lines()
            .filter(|l| !l.starts_with("W007"))
            .collect::<Vec<_>>()
            .join("\n");
        assert!(!filtered.contains("W007"), "W007 should be suppressed by allow list");
    }

}

// ── v12100_tests (v12.1.0) — bind 再束縛禁止 E0018 ────────────────────────────

#[cfg(test)]
mod v12100_tests {
    fn check_with_checker_fav(src: &str, name: &str) -> Result<(), Vec<String>> {
        let tmp = std::env::temp_dir().join(format!("fav_e0018_{}.fav", name));
        std::fs::write(&tmp, src).unwrap();
        let path = tmp.to_str().unwrap();
        let source = super::load_file(path);
        let program = crate::frontend::parser::Parser::parse_str(&source, path)
            .expect("parse error");
        let prog_vm = crate::middle::ast_lower_checker::lower_program(&program);
        crate::checker_fav_runner::run_checker_fav(prog_vm)
    }

    fn assert_e0018(result: Result<(), Vec<String>>, label: &str) {
        assert!(result.is_err(), "{}: expected E0018 error, got Ok", label);
        let msgs = result.unwrap_err();
        assert!(
            msgs.iter().any(|m| m.contains("E0018")),
            "{}: expected E0018 in errors, got: {:?}", label, msgs
        );
    }

    // ── 正常系 ────────────────────────────────────────────────────────────────

    #[test]
    fn e0018_underscore_allowed() {
        // bind _ は何度でも許可
        let src = r#"
fn ok_fn() -> Int !IO {
  bind _ <- IO.println("a")
  bind _ <- IO.println("b")
  0
}
public fn main() -> Int { 0 }
"#;
        let result = check_with_checker_fav(src, "underscore_ok");
        assert!(result.is_ok(), "bind _ multiple times should be OK: {:?}", result.err());
    }

    #[test]
    fn e0018_match_arm_independent() {
        // match arm は独立したスコープ — 別 arm で同名変数は OK
        let src = r#"
fn ok_match(n: Int) -> Int {
  match n {
    Ok(x) => x
    Err(x) => 0
  }
}
public fn main() -> Int { 0 }
"#;
        let result = check_with_checker_fav(src, "arm_ok");
        assert!(result.is_ok(), "same name in different match arms should be OK: {:?}", result.err());
    }

    #[test]
    fn e0018_lambda_scope_independent() {
        // 別々の fn は独立したスコープ — 同名変数を持てる
        let src = r#"
fn outer() -> Int {
  bind x <- 1
  x
}
fn inner() -> Int {
  bind x <- 2
  x
}
public fn main() -> Int { 0 }
"#;
        let result = check_with_checker_fav(src, "lambda_ok");
        assert!(result.is_ok(), "separate fns have independent scopes: {:?}", result.err());
    }

    // ── 異常系 ────────────────────────────────────────────────────────────────

    #[test]
    fn e0018_bind_rebind_detected() {
        // 同名 bind を 2 回 → E0018
        let src = r#"
fn bad(n: Int) -> Int {
  bind x <- n
  bind x <- n
  x
}
public fn main() -> Int { 0 }
"#;
        assert_e0018(check_with_checker_fav(src, "bind_rebind"), "e0018_bind_rebind_detected");
    }

    #[test]
    fn e0018_chain_rebind_detected() {
        // chain x を 2 回 → E0018
        let src = r#"
fn bad_chain(n: Int) -> Int {
  chain x <- n
  chain x <- n
  x
}
public fn main() -> Int { 0 }
"#;
        assert_e0018(check_with_checker_fav(src, "chain_rebind"), "e0018_chain_rebind_detected");
    }

    #[test]
    fn e0018_bind_then_chain_cross() {
        // bind x → chain x（クロスキーワード）→ E0018
        let src = r#"
fn bad_cross(n: Int) -> Int {
  bind x <- n
  chain x <- n
  x
}
public fn main() -> Int { 0 }
"#;
        assert_e0018(check_with_checker_fav(src, "bind_chain_cross"), "e0018_bind_then_chain_cross");
    }

    #[test]
    fn e0018_chain_then_bind_cross() {
        // chain x → bind x（逆順クロス）→ E0018
        let src = r#"
fn bad_cross2(n: Int) -> Int {
  chain x <- n
  bind x <- n
  x
}
public fn main() -> Int { 0 }
"#;
        assert_e0018(check_with_checker_fav(src, "chain_bind_cross"), "e0018_chain_then_bind_cross");
    }

    #[test]
    fn e0018_param_shadowing_fn() {
        // fn パラメータ名と同名の bind → E0018
        let src = r#"
fn compute(x: Int) -> Int {
  bind x <- x
  x
}
public fn main() -> Int { 0 }
"#;
        assert_e0018(check_with_checker_fav(src, "param_fn"), "e0018_param_shadowing_fn");
    }

    #[test]
    fn e0018_param_shadowing_stage() {
        // stage |input| と同名の bind → E0018
        let src = r#"
public stage BadStage: Int -> Int = |input| {
  bind input <- input
  input
}
public fn main() -> Int { 0 }
"#;
        assert_e0018(check_with_checker_fav(src, "param_stage"), "e0018_param_shadowing_stage");
    }

    #[test]
    fn e0018_triple_rebind() {
        // 3 回以上の再束縛でも E0018 が出ること
        let src = r#"
fn triple(n: Int) -> Int {
  bind x <- n
  bind x <- n
  bind x <- n
  x
}
public fn main() -> Int { 0 }
"#;
        assert_e0018(check_with_checker_fav(src, "triple"), "e0018_triple_rebind");
    }
}

