// ── v176000_tests (v17.6.0) — fav bench 統計強化 ─────────────────────────────
#[cfg(test)]
mod v176000_tests {
    use super::{compute_bench_stats, bench_stats_to_json, collect_bench_cases, BenchStats};
    use crate::frontend::parser::Parser;


    #[test]
    fn bench_def_parses() {
        let src = r#"bench "transform rows" { 1 + 1 }"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let has_bench = prog.items.iter().any(|i| matches!(i, crate::ast::Item::BenchDef(_)));
        assert!(has_bench, "bench def should be parsed");
    }

    #[test]
    fn bench_stats_computed() {
        let timings = vec![10.0, 20.0, 30.0, 40.0, 50.0, 60.0, 70.0, 80.0, 90.0, 100.0];
        let stats = compute_bench_stats("test", timings);
        assert_eq!(stats.runs, 10);
        assert!((stats.avg_us - 55.0).abs() < 1.0, "avg should be ~55");
        assert!((stats.min_us - 10.0).abs() < 1.0, "min should be 10");
        assert!((stats.max_us - 100.0).abs() < 1.0, "max should be 100");
        assert!(stats.p50_us >= 40.0 && stats.p50_us <= 60.0, "p50 should be around 50");
    }

    #[test]
    fn bench_filter_option() {
        let src = "bench \"transform rows\" { 1 + 1 }\nbench \"json parse\" { 2 + 2 }\n";
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let programs = vec![("test.fav".to_string(), prog)];
        let (filtered, total) = collect_bench_cases(programs, Some("transform"));
        assert_eq!(total, 2, "should find 2 benches total");
        assert_eq!(filtered.len(), 1, "filter should match 1 bench");
        assert_eq!(filtered[0].1, "transform rows");
    }

    #[test]
    fn bench_json_output() {
        let stats = vec![BenchStats {
            name: "my bench".to_string(),
            runs: 100,
            avg_us: 1234.5,
            p50_us: 1200.0,
            p95_us: 1500.0,
            min_us: 1000.0,
            max_us: 2000.0,
        }];
        let json = bench_stats_to_json(&stats);
        assert!(json.contains("\"benchmarks\""), "json should have benchmarks key");
        assert!(json.contains("\"my bench\""), "json should have bench name");
        assert!(json.contains("\"avg_us\""), "json should have avg_us");
        assert!(json.contains("\"p50_us\""), "json should have p50_us");
        assert!(json.contains("\"p95_us\""), "json should have p95_us");
    }
}

// ── v174000_tests (v17.4.0) — `let` バインディング ───────────────────────────────
#[cfg(test)]
// ── v175000_tests (v17.5.0) — REPL 品質向上 ──────────────────────────────────
#[cfg(test)]
mod v175000_tests {
    use super::{repl_doc_str, repl_complete_prefix, handle_load_cmd, handle_paste_block, ReplSession};

    #[test]
    fn repl_doc_command() {
        // repl_doc_str("List.map") が Some を返しシグネチャを含む
        let doc = repl_doc_str("List.map");
        assert!(doc.is_some(), "List.map should have documentation");
        let doc = doc.unwrap();
        assert!(doc.contains("List<"), "doc should mention List type");
        assert!(doc.contains("List.map"), "doc should contain function name");
    }

    #[test]
    fn repl_type_command_basic() {
        // repl_complete_prefix で :type を補完できる
        let completions = repl_complete_prefix(":ty");
        assert!(completions.iter().any(|s| s.starts_with(":type")),
            "':ty' should complete to ':type'");
    }

    #[test]
    fn repl_load_file() {
        // 一時ファイルを作成し handle_load_cmd でセッションに取り込める
        let dir = tempfile::tempdir().expect("tempdir");
        let path = dir.path().join("helpers.fav");
        std::fs::write(&path, "fn double(x: Int) -> Int { x * 2 }\n")
            .expect("write");
        let mut session = ReplSession::new();
        handle_load_cmd(path.to_str().unwrap(), &mut session);
        assert!(session.def_names.contains(&"double".to_string()),
            "double should be loaded into session");
    }

    #[test]
    fn repl_paste_mode() {
        // handle_paste_block で複数行定義をセッションに追加できる
        let mut session = ReplSession::new();
        handle_paste_block("fn triple(x: Int) -> Int { x * 3 }", &mut session);
        assert!(session.def_names.contains(&"triple".to_string()),
            "triple should be in session after paste");
    }
}

// ── v174000_tests (v17.4.0) — let 除去・bind 非 Result 動作確認 ───────────────
#[cfg(test)]
mod v174000_tests {
    use super::{build_artifact, exec_artifact_main};
    use crate::frontend::parser::Parser;
    use crate::value::Value;

    fn run(src: &str) -> Value {
        let program = Parser::parse_str(src, "v174000_test.fav").expect("parse");
        let artifact = build_artifact(&program);
        exec_artifact_main(&artifact, None).expect("exec")
    }

    #[test]
    fn bind_non_result_basic() {
        // bind は非 Result 値でも使える
        let result = run(r#"
fn main() -> Int {
    bind x <- 42
    bind y <- 8
    x + y
}
"#);
        assert_eq!(result, Value::Int(50));
    }

    #[test]
    fn bind_non_result_string() {
        // bind で String 値を束縛できる
        let result = run(r#"
fn main() -> Int {
    bind name <- String.trim("  hello  ")
    String.length(name)
}
"#);
        assert_eq!(result, Value::Int(5));
    }

    #[test]
    fn bind_mix_result_and_non_result() {
        // bind は式の値をそのまま束縛する（unwrap しない）
        let result = run(r#"
fn main() -> Int {
    bind x <- 10
    bind y <- 20
    bind sum <- x + y
    sum
}
"#);
        assert_eq!(result, Value::Int(30));
    }

    #[test]
    fn bind_with_list_comp() {
        // bind で list comprehension 結果を束縛
        let result = run(r#"
fn main() -> Int {
    bind ns <- List.push(List.push(List.singleton(1), 2), 3)
    bind doubled <- [x * 2 | x <- ns]
    List.length(doubled)
}
"#);
        assert_eq!(result, Value::Int(3));
    }

    #[test]
    fn let_keyword_not_recognized() {
        // 'let' はキーワードではなくなった（parse error になる）
        let result = Parser::parse_str(
            "fn main() -> Int { let x = 42\n x }",
            "test.fav",
        );
        assert!(result.is_err(), "let should not be a valid keyword");
    }
}

// ── v173000_tests (v17.3.0) — コレクション内包表記 ──────────────────────────────
#[cfg(test)]
mod v173000_tests {
    use super::{build_artifact, exec_artifact_main};
    use crate::frontend::parser::Parser;
    use crate::value::Value;

    fn run(src: &str) -> Value {
        let program = Parser::parse_str(src, "v173000_test.fav").expect("parse");
        let artifact = build_artifact(&program);
        exec_artifact_main(&artifact, None).expect("exec")
    }

    fn run_result(src: &str) -> Result<Value, String> {
        let program = Parser::parse_str(src, "v173000_test.fav").expect("parse");
        let artifact = build_artifact(&program);
        exec_artifact_main(&artifact, None)
    }

    #[test]
    #[ignore = "historical version check"]
    fn version_is_17_3_0() {
        let cargo = include_str!("../Cargo.toml");
        assert!(cargo.contains("\"17.3.0\""), "Cargo.toml should have version 17.3.0");
    }

    #[test]
    fn list_comp_map() {
        // [x * 2 | x <- ns] が List.map 相当の結果を返す
        let result = run(r#"
fn main() -> Int {
    bind ns <- List.push(List.push(List.singleton(1), 2), 3)
    bind doubled <- [x * 2 | x <- ns]
    List.length(doubled)
}
"#);
        // [2, 4, 6] → length 3
        assert_eq!(result, Value::Int(3));
    }

    #[test]
    fn list_comp_filter() {
        // [x | x <- ns, x > 2] が List.filter 相当の結果を返す
        let result = run(r#"
fn main() -> Int {
    bind ns <- List.push(List.push(List.push(List.singleton(1), 2), 3), 4)
    bind big <- [x | x <- ns, x > 2]
    List.length(big)
}
"#);
        // [3, 4] → length 2
        assert_eq!(result, Value::Int(2));
    }

    #[test]
    fn list_comp_multi_source() {
        // [Pair(a, b) | a <- as, b <- bs] が直積を返す
        let result = run(r#"
type Pair = | Pair(Int, Int)
fn main() -> Int {
    bind as_ <- List.push(List.singleton(1), 2)
    bind bs  <- List.push(List.singleton(10), 20)
    bind pairs <- [Pair(a, b) | a <- as_, b <- bs]
    List.length(pairs)
}
"#);
        // 2 × 2 = 4 pairs
        assert_eq!(result, Value::Int(4));
    }

    #[test]
    fn result_comp_propagation() {
        // [? f(x) | x <- xs] — エラーが伝播して全体が err になる
        let result = run(r#"
fn safe_div(n: Int) -> Result<Int, String> {
    if n == 0 {
        Result.err("zero!")
    } else {
        Result.ok(100 / n)
    }
}
fn main() -> Bool {
    bind xs <- List.push(List.push(List.singleton(1), 0), 4)
    bind r  <- [? safe_div(x) | x <- xs]
    match r {
        ok(_)  => false
        err(_) => true
    }
}
"#);
        // safe_div(0) = err → whole result is err → true
        assert_eq!(result, Value::Bool(true));
    }
}

// ── v172000_tests (v17.2.0) — パターンマッチ拡張（or-pattern / list-pattern / guard）────
#[cfg(test)]
mod v172000_tests {
    use super::{build_artifact, exec_artifact_main};
    use crate::frontend::parser::Parser;
    use crate::value::Value;

    fn run(src: &str) -> Value {
        let program = Parser::parse_str(src, "v172000_test.fav").expect("parse");
        let artifact = build_artifact(&program);
        exec_artifact_main(&artifact, None).expect("exec")
    }

    #[test]
    #[ignore = "historical version check"]
    fn version_is_17_2_0() {
        let cargo = include_str!("../Cargo.toml");
        assert!(cargo.contains("\"17.2.0\""), "Cargo.toml should have version 17.2.0");
    }

    #[test]
    fn or_pattern_string() {
        // "active" | "pending" => 1, その他 => 0
        let result = run(r#"
fn classify(status: String) -> Int {
    match status {
        "active" | "pending" => 1
        _ => 0
    }
}
fn main() -> Int {
    bind a <- classify("active")
    bind b <- classify("pending")
    bind c <- classify("deleted")
    a + b + c
}
"#);
        assert_eq!(result, Value::Int(2));
    }

    #[test]
    fn list_pattern_head_tail() {
        // [h, ..t] で先頭と残りに分解できる
        let result = run(r#"
fn head_of(xs: List<Int>) -> Int {
    match xs {
        [h, ..t] => h
        _ => 0
    }
}
fn tail_len(xs: List<Int>) -> Int {
    match xs {
        [h, ..t] => List.length(t)
        _ => 0
    }
}
fn main() -> Int {
    bind xs <- List.push(List.push(List.singleton(10), 20), 30)
    bind h <- head_of(xs)
    bind tl <- tail_len(xs)
    h + tl
}
"#);
        // head = 10, tail length = 2 → 12
        assert_eq!(result, Value::Int(12));
    }

    #[test]
    fn list_pattern_empty_single() {
        // [] と [x] パターンが動作する
        let result = run(r#"
fn describe(xs: List<Int>) -> Int {
    match xs {
        [] => 0
        [x] => 1
        _ => 2
    }
}
fn main() -> Int {
    bind a <- describe(List.empty())
    bind b <- describe(List.singleton(42))
    bind c <- describe(List.push(List.push(List.singleton(1), 2), 3))
    a + b + c
}
"#);
        assert_eq!(result, Value::Int(3));
    }

    #[test]
    fn match_guard() {
        // guard 条件: { amount: a } if a > 0.0 => ...
        let result = run(r#"
type Row = { amount: Float }
fn classify(row: Row) -> Int {
    match row {
        { amount: a } if a > 0.0 => 1
        _ => 0
    }
}
fn main() -> Int {
    bind r1 <- Row { amount: 5.0 }
    bind r2 <- Row { amount: 0.0 }
    classify(r1) + classify(r2)
}
"#);
        assert_eq!(result, Value::Int(1));
    }
}

// ── v171000_tests (v17.1.0) — 境界付きジェネリクス（Bounded Generics）─────────
#[cfg(test)]
mod v171000_tests {
    use super::{build_artifact, exec_artifact_main};
    use crate::frontend::parser::Parser;
    use crate::middle::checker::Checker;
    use crate::value::Value;

    fn run(src: &str) -> Value {
        let program = Parser::parse_str(src, "v171000_test.fav").expect("parse");
        let artifact = build_artifact(&program);
        exec_artifact_main(&artifact, None).expect("exec")
    }

    fn check_errors(src: &str) -> Vec<String> {
        let program = Parser::parse_str(src, "v171000_test.fav").expect("parse");
        Checker::check_program(&program)
            .0
            .iter()
            .map(|e| e.code.to_string())
            .collect()
    }

    #[test]
    #[ignore = "historical version check"]
    fn version_is_17_1_0() {
        let cargo = include_str!("../Cargo.toml");
        assert!(cargo.contains("\"17.1.0\""), "Cargo.toml should have version 17.1.0");
    }

    #[test]
    fn bounded_generic_ord_int() {
        // fn max<T with Ord>(a: T, b: T) -> T — Int を渡すと動作する
        let result = run(r#"
fn max<T with Ord>(a: T, b: T) -> T {
    if a > b { a } else { b }
}
fn main() -> Int {
    max(3, 7)
}
"#);
        assert_eq!(result, Value::Int(7));
    }

    #[test]
    fn bounded_generic_ord_float() {
        // Float も Ord を実装している
        let result = run(r#"
fn max<T with Ord>(a: T, b: T) -> T {
    if a > b { a } else { b }
}
fn main() -> Float {
    max(1.5, 2.5)
}
"#);
        assert_eq!(result, Value::Float(2.5));
    }

    #[test]
    fn bounded_generic_serialize_all_types() {
        // Serialize は全型に対して true → String / Int / Bool すべて動作
        let result = run(r#"
fn wrap<T with Serialize>(val: T) -> T {
    val
}
fn main() -> Int {
    wrap(42)
}
"#);
        assert_eq!(result, Value::Int(42));
    }

    #[test]
    fn bounded_generic_multi_bounds() {
        // T with Ord with Serialize — 複数 bound が動作する
        let result = run(r#"
fn max_serializable<T with Ord with Serialize>(a: T, b: T) -> T {
    if a > b { a } else { b }
}
fn main() -> Int {
    max_serializable(10, 20)
}
"#);
        assert_eq!(result, Value::Int(20));
    }

    #[test]
    fn bounded_generic_violation_e0325() {
        // Ord を実装しない Bool 型で E0325 が出る
        let errors = check_errors(r#"
fn max<T with Ord>(a: T, b: T) -> T {
    if a > b { a } else { b }
}
fn main() -> Bool {
    max(true, false)
}
"#);
        assert!(
            errors.iter().any(|e| e == "E0325"),
            "Expected E0325 for Bool not implementing Ord, got: {:?}",
            errors
        );
    }
}

// ── v165000_tests (v16.5.0) — 型エイリアス（alias キーワード）────────────────
#[cfg(test)]
mod v165000_tests {
    use super::{build_artifact, exec_artifact_main};
    use crate::frontend::parser::Parser;
    use crate::value::Value;

    fn run(src: &str) -> Value {
        let program = Parser::parse_str(src, "v165000_test.fav").expect("parse");
        let artifact = build_artifact(&program);
        exec_artifact_main(&artifact, None).expect("exec")
    }

    fn run_str(src: &str) -> String {
        match run(src) {
            Value::Str(s) => s,
            other => panic!("expected Str, got {:?}", other),
        }
    }

    fn run_int(src: &str) -> i64 {
        match run(src) {
            Value::Int(n) => n,
            other => panic!("expected Int, got {:?}", other),
        }
    }

    #[test]
    #[ignore = "historical version check"]
    fn version_is_16_5_0() {
        let cargo = std::fs::read_to_string("Cargo.toml").unwrap();
        assert!(
            cargo.contains("version = \"16.5.0\""),
            "Cargo.toml version should be 16.5.0"
        );
    }

    #[test]
    fn alias_basic() {
        // alias Email = String を使った関数がコンパイル・実行される
        let result = run_str(r#"
alias Email = String

fn greet(e: Email) -> String {
    String.concat("hello ", e)
}

public fn main() -> String {
    greet("alice@example.com")
}
"#);
        assert_eq!(result, "hello alice@example.com");
    }

    #[test]
    fn alias_interchangeable() {
        // alias UserId = Int — String 変数を Email 引数として渡せる
        let result = run_int(r#"
alias UserId = Int

fn double_id(id: UserId) -> Int {
    Math.abs(id) + Math.abs(id)
}

public fn main() -> Int {
    bind raw_id: Int <- 21
    double_id(raw_id)
}
"#);
        assert_eq!(result, 42);
    }

    #[test]
    fn alias_generic() {
        // alias Result2<T> = Result<T, String> — 呼び出しが動作する
        let result = run_str(r#"
alias Result2<T> = Result<T, String>

fn safe_head(xs: List<String>) -> Result2<String> {
    bind first <- List.first(xs)
    match first {
        some(v) => Result.ok(v)
        none    => Result.err("empty list")
    }
}

public fn main() -> String {
    bind items <- List.push(List.empty(), "hello")
    bind r <- safe_head(items)
    match r {
        ok(v)  => v
        err(e) => e
    }
}
"#);
        assert_eq!(result, "hello");
    }

    #[test]
    fn alias_in_signature() {
        // エイリアスを引数型・戻り型に使った fn が正常に動作する
        let result = run_str(r#"
alias Label = String
alias Count = Int

fn describe(name: Label, n: Count) -> Label {
    String.concat(name, String.from_int(n))
}

public fn main() -> String {
    describe("item_", 7)
}
"#);
        assert_eq!(result, "item_7");
    }
}

// ── v163000_tests (v16.3.0) — record spread / update ─────────────────────────
#[cfg(test)]
mod v163000_tests {
    use super::{build_artifact, exec_artifact_main};
    use crate::frontend::parser::Parser;
    use crate::value::Value;

    fn run_int(src: &str) -> i64 {
        let program = Parser::parse_str(src, "record_spread_test.fav").expect("parse");
        let artifact = build_artifact(&program);
        match exec_artifact_main(&artifact, None).expect("exec") {
            Value::Int(n) => n,
            other => panic!("expected Int, got {:?}", other),
        }
    }

    fn run_unit(src: &str) {
        let program = Parser::parse_str(src, "record_spread_test.fav").expect("parse");
        let artifact = build_artifact(&program);
        match exec_artifact_main(&artifact, None).expect("exec") {
            Value::Unit => {}
            other => panic!("expected Unit, got {:?}", other),
        }
    }

    #[test]
    #[ignore = "historical version check"]
    fn version_is_16_3_0() {
        let cargo = std::fs::read_to_string("Cargo.toml").unwrap();
        assert!(
            cargo.contains("version = \"16.3.0\""),
            "Cargo.toml version should be 16.3.0"
        );
    }

    #[test]
    fn record_spread_override_field() {
        // { ...base, y: 10 } overrides y, returns 10
        let result = run_int(r#"
type Point = { x: Int y: Int }
public fn main() -> Int {
    bind p <- Point { x: 1, y: 2 }
    bind q <- { ...p, y: 10 }
    q.y
}
"#);
        assert_eq!(result, 10);
    }

    #[test]
    fn record_spread_preserve_base_field() {
        // { ...base, y: 10 } preserves x from base
        let result = run_int(r#"
type Point = { x: Int y: Int }
public fn main() -> Int {
    bind p <- Point { x: 5, y: 2 }
    bind q <- { ...p, y: 10 }
    q.x
}
"#);
        assert_eq!(result, 5);
    }

    #[test]
    fn record_spread_no_overrides() {
        // { ...base } with no overrides — all fields preserved
        let result = run_int(r#"
type Point = { x: Int y: Int }
public fn main() -> Int {
    bind p <- Point { x: 7, y: 3 }
    bind q <- { ...p }
    q.x
}
"#);
        assert_eq!(result, 7);
    }

    #[test]
    fn record_spread_assert_matches() {
        // verify both fields after spread
        run_unit(r#"
type Point = { x: Int y: Int }
public fn main() -> Unit {
    bind p <- Point { x: 1, y: 2 }
    bind q <- { ...p, x: 99 }
    assert_matches(q, { x: 99, y: 2 })
}
"#);
    }

    #[test]
    fn record_spread_multiple_overrides() {
        // override multiple fields
        let result = run_int(r#"
type Color = { r: Int g: Int b: Int }
public fn main() -> Int {
    bind red <- Color { r: 255, g: 0, b: 0 }
    bind purple <- { ...red, b: 128 }
    purple.b
}
"#);
        assert_eq!(result, 128);
    }
}

// ── v177000_tests (v17.7.0) — forall プロパティベーステスト ───────────────────────
#[cfg(test)]
mod v177000_tests {
    use super::{build_artifact};
    use crate::frontend::parser::Parser;
    use crate::backend::vm::VM;

    fn run_test_fn(src: &str, test_name: &str) -> Result<(), String> {
        let program = Parser::parse_str(src, "v177000_test.fav").map_err(|e| e.to_string())?;
        let artifact = build_artifact(&program);
        let fn_name = format!("$test:{}", test_name);
        let fn_idx = artifact
            .fn_idx_by_name(&fn_name)
            .ok_or_else(|| format!("test fn not found: {}", fn_name))?;
        VM::run(&artifact, fn_idx, vec![])
            .map(|_| ())
            .map_err(|e| e.message)
    }

    #[test]
    fn forall_int_parses() {
        let src = r#"
test "forall int parses" {
  forall n: Int {
    assert_true(Math.abs(n) >= 0 || Math.abs(n) < 0)
  }
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let has_forall = prog.items.iter().any(|i| {
            if let crate::ast::Item::TestDef(t) = i {
                t.body.stmts.iter().any(|s| matches!(s, crate::ast::Stmt::Forall(_)))
            } else {
                false
            }
        });
        assert!(has_forall, "forall stmt should be parsed inside test block");
    }

    #[test]
    fn forall_string_idempotent() {
        let src = r#"
test "trim idempotent" {
  forall s: String {
    bind trimmed <- String.trim(s)
    assert_eq(trimmed, String.trim(trimmed))
  }
}
"#;
        let result = run_test_fn(src, "trim idempotent");
        assert!(result.is_ok(), "forall string idempotent should pass: {:?}", result);
    }

    #[test]
    fn forall_finds_counterexample() {
        let src = r#"
test "all int positive" {
  forall n: Int {
    assert_true(n > 0)
  }
}
"#;
        let result = run_test_fn(src, "all int positive");
        assert!(result.is_err(), "forall should find counterexample for false property");
        let err = result.unwrap_err();
        assert!(
            err.contains("assert") || err.contains("false") || err.contains("counterexample"),
            "error should mention assertion failure, got: {}", err
        );
    }

    #[test]
    fn forall_with_guard() {
        let src = r#"
test "nonzero abs positive" {
  forall n: Int where { n != 0 } {
    bind abs_n <- Math.abs(n)
    assert_true(abs_n > 0)
  }
}
"#;
        let result = run_test_fn(src, "nonzero abs positive");
        assert!(result.is_ok(), "forall with guard should pass: {:?}", result);
    }
}

// ── v178000_tests (v17.8.0) — パッケージシステム成熟 ────────────────────────────
#[cfg(test)]
mod v178000_tests {
    use super::*;
    use crate::lock::{LockFile, LockedPackage};
    use crate::registry::resolver::{parse_semver, parse_version_req, resolve_best};

    #[test]
    fn fav_toml_dependencies_parse() {
        let src = r#"
[rune]
name = "my-pipeline"
version = "1.0.0"

[dependencies]
csv = "^2.0.0"
bigquery = "^1.0.0"

[dev-dependencies]
test-fixtures = "^1.0.0"

[registry]
url = "https://registry.favnir.dev"
"#;
        let toml = crate::toml::parse_fav_toml_pub(src);
        assert!(
            toml.dependencies.iter().any(|d| d.name() == "csv"),
            "csv should be in dependencies"
        );
        assert!(
            toml.dependencies.iter().any(|d| d.name() == "bigquery"),
            "bigquery should be in dependencies"
        );
        assert!(
            toml.dev_dependencies.iter().any(|d| d.name() == "test-fixtures"),
            "test-fixtures should be in dev_dependencies"
        );
        assert_eq!(
            toml.registry_url.as_deref(),
            Some("https://registry.favnir.dev")
        );
    }

    #[test]
    fn fav_lock_generates() {
        let mut lock = LockFile::default();
        lock.packages.push(LockedPackage {
            name: "csv".to_string(),
            version: "2.1.0".to_string(),
            resolved_path: "registry:https://registry.favnir.dev".to_string(),
            checksum: Some("sha256:abc123".to_string()),
            source: Some("registry:https://registry.favnir.dev".to_string()),
        });
        let toml_str = lock.to_toml();
        assert!(toml_str.contains("checksum"), "lock should contain checksum field");
        assert!(toml_str.contains("source"), "lock should contain source field");
        assert!(toml_str.contains("csv"), "lock should contain package name");
        assert!(toml_str.contains("sha256:abc123"), "lock should contain checksum value");
    }

    #[test]
    fn semver_caret_resolve() {
        let req = parse_version_req("^2.0.0").expect("parse req");
        let available = vec![
            parse_semver("1.9.9").unwrap(),
            parse_semver("2.0.0").unwrap(),
            parse_semver("2.1.0").unwrap(),
            parse_semver("3.0.0").unwrap(),
        ];
        let best = resolve_best(&req, &available).expect("should resolve");
        assert_eq!(best.major, 2);
        assert_eq!(best.minor, 1);
        assert_eq!(best.patch, 0);
    }

    #[test]
    fn cmd_add_updates_toml() {
        use std::fs;
        use tempfile::tempdir;

        let dir = tempdir().unwrap();
        let toml_path = dir.path().join("fav.toml");
        fs::write(
            &toml_path,
            "[rune]\nname = \"test\"\nversion = \"1.0.0\"\n",
        )
        .unwrap();

        unsafe { std::env::set_var("REGISTRY_MOCK", "1") };
        let result = cmd_add_impl(dir.path(), "csv", false);
        unsafe { std::env::remove_var("REGISTRY_MOCK") };

        assert!(result.is_ok(), "cmd_add_impl should succeed: {:?}", result);
        let contents = fs::read_to_string(&toml_path).unwrap();
        assert!(
            contents.contains("csv"),
            "fav.toml should contain csv after add, got:\n{}",
            contents
        );
    }
}

